import { useState, useEffect } from 'preact/hooks';

export function useApi<T>(url: string, deps: unknown[] = []) {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);

    fetch(url)
      .then(async (res) => {
        if (res.status === 401) {
          window.location.hash = '#/login';
          return;
        }
        if (!res.ok) {
          const body = (await res.json().catch(() => ({}))) as { error?: string };
          throw new Error(body.error ?? `HTTP ${res.status}`);
        }
        return res.json() as Promise<T>;
      })
      .then((d) => {
        if (!cancelled && d !== undefined) {
          setData(d);
          setLoading(false);
        }
      })
      .catch((err: Error) => {
        if (!cancelled) {
          setError(err.message);
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [url, ...deps]);

  return { data, loading, error };
}

export async function apiPost<T>(
  url: string,
  body: unknown,
): Promise<{ data?: T; error?: string }> {
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = (await res.json().catch(() => ({}))) as T;
    if (!res.ok) return { error: (data as { error?: string }).error ?? `HTTP ${res.status}` };
    return { data };
  } catch (e) {
    return { error: (e as Error).message };
  }
}

export async function apiPatch<T>(
  url: string,
  body: unknown,
): Promise<{ data?: T; error?: string }> {
  try {
    const res = await fetch(url, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = (await res.json().catch(() => ({}))) as T;
    if (!res.ok) return { error: (data as { error?: string }).error ?? `HTTP ${res.status}` };
    return { data };
  } catch (e) {
    return { error: (e as Error).message };
  }
}

import { useEffect, useState } from 'preact/hooks';
import { useApi } from '../hooks/useApi.js';
import { StatBadge } from '../components/StatBadge.js';
import { DataTable } from '../components/DataTable.js';
import { IntegrityBadge } from '../components/IntegrityBadge.js';

interface MatchRow {
  id: string;
  player_1_name: string;
  player_2_name: string;
  bot_strategy: string | null;
  status: string;
  outcome: { victoryType?: string; winnerName?: string } | null;
  created_at: string;
  total_turns: number;
  verified_turns: number;
}

interface UserRow {
  id: string;
}

function timeAgo(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  return `${Math.floor(diff / 86400000)}d ago`;
}

export function Dashboard() {
  const { data: activeMatches } = useApi<MatchRow[]>('/admin-api/matches?status=active');
  const { data: recentMatches } = useApi<MatchRow[]>(
    '/admin-api/matches?status=completed&limit=20',
  );
  const { data: users } = useApi<UserRow[]>('/admin-api/users?limit=1');
  const [, setTick] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setTick((t) => t + 1);
    }, 30000);
    return () => {
      clearInterval(interval);
    };
  }, []);

  const today = new Date().toDateString();
  const todayCount = (recentMatches ?? []).filter(
    (m) => new Date(m.created_at).toDateString() === today,
  ).length;
  const botPct =
    recentMatches && recentMatches.length > 0
      ? Math.round(
          ((recentMatches ?? []).filter((m) => m.bot_strategy).length / recentMatches.length) * 100,
        )
      : 0;

  return (
    <div class="page">
      <h1 class="page-title">Dashboard</h1>
      <p class="page-subtitle">Live operations overview — refreshes every 30s</p>

      <div class="stat-grid">
        <StatBadge
          label="Active Matches"
          value={(activeMatches ?? []).length}
          color="var(--green)"
        />
        <StatBadge label="Today's Matches" value={todayCount} />
        <StatBadge label="Total Users" value={users?.length ?? '...'} />
        <StatBadge label="Bot Match %" value={`${botPct}%`} color="var(--blue)" />
      </div>

      <div class="card" style={{ marginBottom: '16px' }}>
        <div class="card-title">Live Matches ({(activeMatches ?? []).length})</div>
        <DataTable<MatchRow>
          columns={[
            {
              key: 'id',
              label: 'Match ID',
              render: (r) => (
                <a href={`#/matches/${r.id}`} class="mono">
                  {r.id.slice(0, 8)}...
                </a>
              ),
            },
            {
              key: 'players',
              label: 'Players',
              render: (r) => `${r.player_1_name} vs ${r.player_2_name}`,
            },
            { key: 'bot', label: 'Bot', render: (r) => r.bot_strategy ?? '—' },
            { key: 'created_at', label: 'Started', render: (r) => timeAgo(r.created_at) },
          ]}
          rows={activeMatches ?? []}
          keyFn={(r) => r.id}
        />
      </div>

      <div class="card">
        <div class="card-title">Recent Matches</div>
        <DataTable<MatchRow>
          columns={[
            {
              key: 'id',
              label: 'Match ID',
              render: (r) => (
                <a href={`#/matches/${r.id}`} class="mono">
                  {r.id.slice(0, 8)}...
                </a>
              ),
            },
            { key: 'winner', label: 'Winner', render: (r) => r.outcome?.winnerName ?? '—' },
            { key: 'victory', label: 'Victory', render: (r) => r.outcome?.victoryType ?? '—' },
            { key: 'turns', label: 'Turns', render: (r) => String(r.total_turns) },
            {
              key: 'integrity',
              label: 'Check',
              render: (r) => <IntegrityBadge ok={r.verified_turns === r.total_turns} />,
            },
            { key: 'created_at', label: 'Ended', render: (r) => timeAgo(r.created_at) },
          ]}
          rows={recentMatches ?? []}
          keyFn={(r) => r.id}
        />
      </div>
    </div>
  );
}

import { useState } from 'preact/hooks';
import { useApi } from '../hooks/useApi.js';
import { IntegrityBadge } from '../components/IntegrityBadge.js';

interface TransactionEntry {
  action: { type: string; column?: number; cardId?: unknown };
  phaseTrace: string[];
  stateHashAfter: string;
  turnHash?: string;
}

interface EventEntry {
  id: string;
  type: string;
  name: string;
  timestamp: string;
  status: string;
}

interface Match {
  id: string;
  player_1_name: string;
  player_2_name: string;
  bot_strategy: string | null;
  status: string;
  outcome: { victoryType?: string; winnerName?: string; winnerId?: string } | null;
  transaction_log: TransactionEntry[];
  event_log: { events: EventEntry[] } | null;
  event_log_fingerprint: string | null;
  config: unknown;
  created_at: string;
}

function actionDsl(action: TransactionEntry['action']): string {
  if (action.type === 'deploy') return `A:${action.column}:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'discard') return `D:${action.column}:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'reinforcement') return `R:${String(action.cardId).slice(0, 6)}`;
  if (action.type === 'pass') return 'P';
  if (action.type === 'forfeit') return 'F';
  return action.type;
}

export function MatchDetail({ matchId }: { matchId: string }) {
  const { data: match, loading, error } = useApi<Match>(`/admin-api/matches/${matchId}`);
  const [tab, setTab] = useState<'overview' | 'txlog' | 'eventlog' | 'config'>('overview');

  if (loading)
    return (
      <div class="page">
        <p style={{ color: 'var(--text-dim)' }}>Loading...</p>
      </div>
    );
  if (error || !match)
    return (
      <div class="page">
        <p class="error-msg">{error ?? 'Match not found'}</p>
      </div>
    );

  const txLog = match.transaction_log ?? [];
  const verifiedTurns = txLog.filter((e) => e.turnHash).length;

  return (
    <div class="page">
      <h1 class="page-title">
        Match{' '}
        <span class="mono" style={{ fontSize: '16px' }}>
          {match.id.slice(0, 8)}...
        </span>
      </h1>
      <p class="page-subtitle">
        {match.player_1_name} vs {match.player_2_name} — <strong>{match.status}</strong>
      </p>

      <div class="tabs">
        {(['overview', 'txlog', 'eventlog', 'config'] as const).map((t) => (
          <div
            key={t}
            class={`tab${tab === t ? ' active' : ''}`}
            onClick={() => {
              setTab(t);
            }}
          >
            {t === 'txlog'
              ? 'Transaction Log'
              : t === 'eventlog'
                ? 'Event Log'
                : t === 'config'
                  ? 'Config'
                  : 'Overview'}
          </div>
        ))}
      </div>

      {tab === 'overview' && (
        <div class="two-col">
          <div class="card">
            <div class="card-title">Integrity</div>
            <div class="kv-list">
              <span class="k">turnHash coverage</span>
              <span>
                {verifiedTurns} / {txLog.length}{' '}
                <IntegrityBadge ok={verifiedTurns === txLog.length} />
              </span>
              <span class="k">event log fingerprint</span>
              <span>
                <IntegrityBadge ok={!!match.event_log_fingerprint} />
              </span>
            </div>
          </div>
          <div class="card">
            <div class="card-title">Outcome</div>
            {match.outcome ? (
              <div class="kv-list">
                {Object.entries(match.outcome).map(([k, v]) => (
                  <>
                    <span class="k">{k}</span>
                    <span>{v ?? ''}</span>
                  </>
                ))}
              </div>
            ) : (
              <p style={{ color: 'var(--text-dim)' }}>No outcome yet</p>
            )}
          </div>
        </div>
      )}

      {tab === 'txlog' && (
        <div class="card">
          <div class="card-title">Transaction Log ({txLog.length} entries)</div>
          <p style={{ fontSize: '12px', color: 'var(--text-dim)', marginBottom: '12px' }}>
            turnHash presence check only. For full re-derivation, use the "turnHash sweep" report.
          </p>
          <div style={{ overflowX: 'auto' }}>
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Action (DSL)</th>
                  <th>Phase After</th>
                  <th>stateHash</th>
                  <th>turnHash</th>
                  <th>Check</th>
                </tr>
              </thead>
              <tbody>
                {txLog.map((entry, i) => (
                  <tr key={i}>
                    <td>{i + 1}</td>
                    <td class="mono">{actionDsl(entry.action)}</td>
                    <td class="mono">{entry.phaseTrace?.[entry.phaseTrace.length - 1] ?? '—'}</td>
                    <td class="mono" style={{ fontSize: '11px' }}>
                      {entry.stateHashAfter?.slice(0, 12)}...
                    </td>
                    <td class="mono" style={{ fontSize: '11px' }}>
                      {entry.turnHash ? `${entry.turnHash.slice(0, 12)}...` : '—'}
                    </td>
                    <td>
                      <IntegrityBadge ok={!!entry.turnHash} />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {tab === 'eventlog' && (
        <div class="card">
          <div class="card-title">Event Log ({(match.event_log?.events ?? []).length} events)</div>
          <div style={{ overflowX: 'auto' }}>
            <table>
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Type</th>
                  <th>Name</th>
                  <th>Status</th>
                  <th>Timestamp</th>
                </tr>
              </thead>
              <tbody>
                {(match.event_log?.events ?? []).map((evt) => (
                  <tr key={evt.id}>
                    <td class="mono" style={{ fontSize: '11px' }}>
                      {evt.id?.slice(0, 12)}...
                    </td>
                    <td>{evt.type}</td>
                    <td>{evt.name}</td>
                    <td>{evt.status}</td>
                    <td class="mono" style={{ fontSize: '11px' }}>
                      {evt.timestamp}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {tab === 'config' && (
        <div class="card">
          <div class="card-title">Match Config</div>
          <pre>{JSON.stringify(match.config, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

import { useState } from 'preact/hooks';
import { useApi, apiPost } from '../hooks/useApi.js';
import { SqlBlock } from '../components/SqlBlock.js';
import { DataTable } from '../components/DataTable.js';

interface ReportParam {
  name: string;
  type: 'select' | 'number';
  default: string | number;
  options?: string[];
  label: string;
}

interface Report {
  id: string;
  name: string;
  description: string;
  category: 'matches' | 'players' | 'integrity';
  params: ReportParam[];
}

interface RunResult {
  rows: Record<string, unknown>[];
  rowCount: number;
  durationMs: number;
  sql: string;
}

function exportCsv(rows: Record<string, unknown>[]) {
  if (!rows.length) return;
  const keys = Object.keys(rows[0] ?? {});
  const lines = [
    keys.join(','),
    ...rows.map((r) => keys.map((k) => JSON.stringify(r[k] ?? '')).join(',')),
  ];
  const blob = new Blob([lines.join('\n')], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'report.csv';
  a.click();
  URL.revokeObjectURL(url);
}

export function Reports() {
  const { data: reports } = useApi<Report[]>('/admin-api/reports');
  const [selected, setSelected] = useState<Report | null>(null);
  const [params, setParams] = useState<Record<string, string | number>>({});
  const [sqlPreview, setSqlPreview] = useState<string | null>(null);
  const [result, setResult] = useState<RunResult | null>(null);
  const [runError, setRunError] = useState<string | null>(null);
  const [running, setRunning] = useState(false);

  const selectReport = async (report: Report) => {
    const initialParams: Record<string, string | number> = {};
    for (const p of report.params) initialParams[p.name] = p.default;
    setSelected(report);
    setParams(initialParams);
    setResult(null);
    setRunError(null);

    const qs = new URLSearchParams(
      Object.entries(initialParams).map(([k, v]) => [k, String(v)]),
    ).toString();
    const res = await fetch(`/admin-api/reports/${report.id}/sql?${qs}`);
    if (res.ok) {
      const { sql } = (await res.json()) as { sql: string };
      setSqlPreview(sql);
    }
  };

  const updateParam = async (name: string, value: string | number) => {
    const newParams = { ...params, [name]: value };
    setParams(newParams);
    if (!selected) return;
    const qs = new URLSearchParams(
      Object.entries(newParams).map(([k, v]) => [k, String(v)]),
    ).toString();
    const res = await fetch(`/admin-api/reports/${selected.id}/sql?${qs}`);
    if (res.ok) {
      const { sql } = (await res.json()) as { sql: string };
      setSqlPreview(sql);
    }
  };

  const runReport = async () => {
    if (!selected) return;
    setRunning(true);
    setRunError(null);
    const { data, error } = await apiPost<RunResult>(
      `/admin-api/reports/${selected.id}/run`,
      params,
    );
    setRunning(false);
    if (error) {
      setRunError(error);
      return;
    }
    if (data) setResult(data);
  };

  const grouped = (reports ?? []).reduce<Record<string, Report[]>>((acc, r) => {
    (acc[r.category] ??= []).push(r);
    return acc;
  }, {});

  return (
    <div class="page">
      <h1 class="page-title">Reports</h1>
      <p class="page-subtitle">Pre-built SQL reports — params are validated server-side</p>

      <div class="sidebar-layout">
        <div class="sidebar">
          {Object.entries(grouped).map(([cat, items]) => (
            <div key={cat}>
              <div class="sidebar-group-label">{cat}</div>
              {items.map((r) => (
                <div
                  key={r.id}
                  class={`sidebar-item${selected?.id === r.id ? ' active' : ''}`}
                  onClick={() => {
                    void selectReport(r);
                  }}
                >
                  {r.name}
                </div>
              ))}
            </div>
          ))}
        </div>

        <div>
          {!selected && (
            <p style={{ color: 'var(--text-dim)' }}>Select a report from the sidebar</p>
          )}
          {selected && (
            <>
              <div class="card" style={{ marginBottom: '12px' }}>
                <div class="card-title">{selected.name}</div>
                <p style={{ color: 'var(--text-dim)', marginBottom: '12px', fontSize: '13px' }}>
                  {selected.description}
                </p>

                {selected.params.length > 0 && (
                  <div
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
                      gap: '12px',
                      marginBottom: '12px',
                    }}
                  >
                    {selected.params.map((p) => (
                      <div class="form-group" key={p.name} style={{ marginBottom: 0 }}>
                        <label>{p.label}</label>
                        {p.type === 'select' ? (
                          <select
                            value={String(params[p.name] ?? p.default)}
                            onChange={(e) => {
                              void updateParam(p.name, (e.target as HTMLSelectElement).value);
                            }}
                          >
                            {(p.options ?? []).map((opt) => (
                              <option key={opt} value={opt}>
                                {opt}
                              </option>
                            ))}
                          </select>
                        ) : (
                          <input
                            type="number"
                            value={Number(params[p.name] ?? p.default)}
                            onInput={(e) => {
                              void updateParam(
                                p.name,
                                parseInt((e.target as HTMLInputElement).value, 10),
                              );
                            }}
                          />
                        )}
                      </div>
                    ))}
                  </div>
                )}

                {sqlPreview && <SqlBlock sql={sqlPreview} />}

                <button
                  class="primary"
                  onClick={() => void runReport()}
                  disabled={running}
                  style={{ marginTop: '12px' }}
                >
                  {running ? 'Running...' : 'Run Report'}
                </button>
              </div>

              {runError && <p class="error-msg">{runError}</p>}

              {result && (
                <div class="card">
                  <div
                    style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      marginBottom: '12px',
                    }}
                  >
                    <div class="card-title" style={{ marginBottom: 0 }}>
                      {result.rowCount} rows — {result.durationMs}ms
                    </div>
                    <button
                      onClick={() => {
                        exportCsv(result.rows);
                      }}
                    >
                      Export CSV
                    </button>
                  </div>
                  {result.rows.length > 0 && (
                    <DataTable
                      columns={Object.keys(result.rows[0] ?? {}).map((k) => ({
                        key: k,
                        label: k,
                        render: (r: Record<string, unknown>) =>
                          k === 'id' ? (
                            <a href={`#/matches/${String(r[k])}`} class="mono">
                              {String(r[k]).slice(0, 8)}...
                            </a>
                          ) : (
                            String(r[k] ?? '')
                          ),
                      }))}
                      rows={result.rows}
                      keyFn={(_, i) => String(i)}
                    />
                  )}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

/**
 * Required env vars:
 *   DATABASE_URL             — Neon Postgres connection string
 *   JWT_SECRET               — Shared with game server
 *   GAME_SERVER_INTERNAL_URL — e.g. http://phalanxduel.internal:3001
 *   ADMIN_INTERNAL_TOKEN     — Secret for POST /internal/matches
 * Optional:
 *   PORT                     — Default: 3002
 *   NODE_ENV                 — 'production' | 'development' | 'test'
 */
import './instrument.js';
import { resolve, dirname } from 'node:path';
import { existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import Fastify from 'fastify';
import fastifyCookie from '@fastify/cookie';
import fastifyJwt from '@fastify/jwt';
import fastifyStatic from '@fastify/static';
import { registerLoginRoute } from './routes/login.js';
import { registerMatchRoutes } from './routes/matches.js';
import { registerUserRoutes } from './routes/users.js';
import { registerReportRoutes } from './routes/reports.js';
import { checkPendingMigrations } from './check-migrations.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

export async function buildAdminApp() {
  const app = Fastify({ logger: process.env.NODE_ENV !== 'test' });

  await app.register(fastifyCookie);
  await app.register(fastifyJwt, {
    secret: process.env.JWT_SECRET ?? 'phalanx-dev-secret',
    cookie: { cookieName: 'admin_token', signed: false },
  });

  registerLoginRoute(app);
  registerMatchRoutes(app);
  registerUserRoutes(app);
  registerReportRoutes(app);

  const clientDist = resolve(__dirname, '../../dist/client');
  if (existsSync(clientDist)) {
    await app.register(fastifyStatic, { root: clientDist, prefix: '/' });
    app.setNotFoundHandler((_req, reply) => void reply.sendFile('index.html'));
  }

  return app;
}

async function main() {
  await checkPendingMigrations();
  const app = await buildAdminApp();
  const port = parseInt(process.env.PHALANX_ADMIN_PORT ?? '3002', 10);
  await app.listen({ port, host: '0.0.0.0' });
  console.log(`Admin service listening on port ${port}`);
}

// Only run when this file is the entry point, not when imported by tests
