}

import * as Sentry from '@sentry/node';
import { hostname } from 'node:os';
import { metrics } from '@opentelemetry/api';
import { logs, SeverityNumber } from '@opentelemetry/api-logs';
import { BatchSpanProcessor, NodeTracerProvider } from '@opentelemetry/sdk-trace-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { OTLPLogExporter } from '@opentelemetry/exporter-logs-otlp-http';
import { MeterProvider, PeriodicExportingMetricReader } from '@opentelemetry/sdk-metrics';
import { BatchLogRecordProcessor, LoggerProvider } from '@opentelemetry/sdk-logs';
import { OTLPMetricExporter } from '@opentelemetry/exporter-metrics-otlp-http';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { ATTR_SERVICE_NAME } from '@opentelemetry/semantic-conventions';

interface MeterProviderWithAddMetricReader {
  addMetricReader(reader: PeriodicExportingMetricReader): void;
}

function hasAddMetricReader(value: unknown): value is MeterProviderWithAddMetricReader {
  return (
    typeof value === 'object' &&
    value !== null &&
    typeof Reflect.get(value, 'addMetricReader') === 'function'
  );
}

function normalizeOtlpEndpoint(endpoint: string): string {
  return endpoint
    .trim()
    .replace(/\/+$/u, '')
    .replace(/\/v1\/(traces|metrics|logs)$/u, '');
}

function envFlagEnabled(value: string | undefined): boolean {
  return value === '1' || value?.toLowerCase() === 'true';
}

const isProduction = process.env.NODE_ENV === 'production';
const sentryDsn = process.env.SENTRY_DSN; // Using the primary DSN for admin project
// OTel collector endpoint with default to localhost:4318 (local development)
const otlpEndpointRaw = process.env.OTEL_EXPORTER_OTLP_ENDPOINT ?? 'http://localhost:4318';
const otlpEndpoint = normalizeOtlpEndpoint(otlpEndpointRaw);
const localSentryEnabled = envFlagEnabled(process.env.PHALANX_ENABLE_LOCAL_SENTRY);
const sentryEnabled = !!sentryDsn && (isProduction || localSentryEnabled);
const otlpConsoleLogsEnabled =
  process.env.OTEL_CONSOLE_LOGS_ENABLED === '1' ||
  process.env.OTEL_CONSOLE_LOGS_ENABLED?.toLowerCase() === 'true';
const serviceName = process.env.OTEL_SERVICE_NAME?.trim() ?? 'phalanxduel';
process.env.OTEL_SERVICE_NAME ??= serviceName;
const resource = resourceFromAttributes({
  [ATTR_SERVICE_NAME]: serviceName,
});

const integrations = [Sentry.consoleLoggingIntegration({ levels: ['log', 'warn', 'error'] })];

// Create OTLP trace exporter (primary telemetry path)
let traceExporter: OTLPTraceExporter | undefined;
try {
  traceExporter = new OTLPTraceExporter({
    url: `${otlpEndpoint}/v1/traces`,
  });
} catch (error) {
  console.warn(
    `[instrument.ts] Failed to initialize OTLP trace exporter at ${otlpEndpoint}:`,
    error instanceof Error ? error.message : error,
  );
}

if (!isProduction) {
  integrations.push(Sentry.spotlightIntegration());
}

// Try to load profiling integration if available
try {
  const { nodeProfilingIntegration } = await import('@sentry/profiling-node');
  if (nodeProfilingIntegration) {
    integrations.push(nodeProfilingIntegration());
  }
} catch {
  // Silently fail profiling if binary is missing or incompatible
}

// Initialize Sentry for error/exception capturing only (not span export).
// Spans are exported via OTLP to the local collector instead.
if (sentryEnabled) {
  Sentry.init({
    dsn: sentryDsn,
    release: process.env.SENTRY_RELEASE ?? `phalanxduel@0.1.0`,
    integrations: (defaults) => [...defaults.filter((i) => i.name !== 'Fastify'), ...integrations],
    enableLogs: true,
    tracesSampleRate: 0,
    profileSessionSampleRate: process.env.SENTRY_PROFILES_SAMPLE_RATE
      ? parseFloat(process.env.SENTRY_PROFILES_SAMPLE_RATE)
      : 1.0,
    profileLifecycle: 'trace',
    environment: process.env.APP_ENV ?? process.env.NODE_ENV ?? 'development',
    debug: !isProduction && !!process.env.SENTRY_DEBUG,
    sendDefaultPii: true,

    initialScope: {
      tags: {
        'host.name': process.env.FLY_MACHINE_ID ?? hostname(),
        'cloud.provider': process.env.FLY_APP_NAME ? 'fly_io' : 'local',
        'cloud.region': process.env.FLY_REGION ?? 'unknown',
      },
    },
  });
} else {
  console.log('[instrument.ts] Sentry not enabled for Admin. Using OTLP for all telemetry.');
}

// ── OTLP Export Integration ─────────────────────────────────────────────────
try {
  const metricExporter = new OTLPMetricExporter({
    url: `${otlpEndpoint}/v1/metrics`,
  });
  const metricReader = new PeriodicExportingMetricReader({
    exporter: metricExporter,
    exportIntervalMillis: 5000,
  });

  if (sentryEnabled && traceExporter) {
    const meterProvider = metrics.getMeterProvider() as unknown;
    if (hasAddMetricReader(meterProvider)) {
      meterProvider.addMetricReader(metricReader);
    } else {
      const fallbackMeterProvider = new MeterProvider({
        resource,
        readers: [metricReader],
      });
      metrics.setGlobalMeterProvider(fallbackMeterProvider);
    }
  } else if (traceExporter) {
    const tracerProvider = new NodeTracerProvider({
      resource,
      spanProcessors: [new BatchSpanProcessor(traceExporter)],
    });
    tracerProvider.register();

    const meterProvider = new MeterProvider({
      resource,
      readers: [metricReader],
    });
    metrics.setGlobalMeterProvider(meterProvider);
  }
} catch (error) {
  console.error(
    '[instrument.ts] Failed to initialize OTLP metric exporter:',
    error instanceof Error ? error.message : error,
  );
}

// ── OTLP Console Log Forwarding (Opt-in) ────────────────────────────────────
if (otlpEndpoint && otlpConsoleLogsEnabled) {
  const CONSOLE_PATCH_FLAG = Symbol.for('phalanx.otel.console.patched');
  const globalObj = globalThis as Record<symbol, boolean>;

  if (!globalObj[CONSOLE_PATCH_FLAG]) {
    globalObj[CONSOLE_PATCH_FLAG] = true;

    const logExporter = new OTLPLogExporter({
      url: `${otlpEndpoint}/v1/logs`,
    });

    const loggerProvider = new LoggerProvider({
      resource,
      processors: [new BatchLogRecordProcessor(logExporter)],
    });
    logs.setGlobalLoggerProvider(loggerProvider);

    const logger = loggerProvider.getLogger('admin.console', '1.0.0');

    const toMessage = (args: unknown[]): string =>
      args
        .map((arg) => {
          if (typeof arg === 'string') return arg;
          if (arg instanceof Error) return arg.stack ?? arg.message;
          try {
            return JSON.stringify(arg);
          } catch {
            return String(arg);
          }
        })
        .join(' ');

    const emit = (severityNumber: SeverityNumber, severityText: string, args: unknown[]) => {
      try {
        logger.emit({
          severityNumber,
          severityText,
          body: toMessage(args),
          attributes: {},
        });
      } catch {
        // Never break runtime behavior if log export fails.
      }
    };

    const originalConsole = {
      log: console.log,
      info: console.info,
      warn: console.warn,
      error: console.error,
    };

    console.log = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.log.apply(console, args);
    };

    console.info = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.info.apply(console, args);
    };

    console.warn = (...args: unknown[]) => {
      emit(SeverityNumber.WARN, 'WARN', args);
      originalConsole.warn.apply(console, args);
    };

    console.error = (...args: unknown[]) => {
      emit(SeverityNumber.ERROR, 'ERROR', args);
      originalConsole.error.apply(console, args);
    };

    const flushLogs = async () => {
      try {
        await loggerProvider.forceFlush();
      } catch {
        // Ignore flush errors on shutdown.
      }
    };
    process.once('beforeExit', () => {
      void flushLogs();
    });
  }
}

import type { FastifyInstance } from 'fastify';
import { sql } from 'drizzle-orm';
import { requireAdmin } from '../middleware/auth.js';
import { db } from '../db.js';

interface ReportParam {
  name: string;
  type: 'select' | 'number';
  default: string | number;
  options?: string[];
  label: string;
}

interface Report {
  id: string;
  name: string;
  description: string;
  category: 'matches' | 'players' | 'integrity';
  params: ReportParam[];
  buildSql: (params: Record<string, string | number>) => string;
}

function safeSelect(value: unknown, options: string[], fallback: string): string {
  return options.includes(String(value)) ? String(value) : fallback;
}

function safeNumber(value: unknown, fallback: number): number {
  const n = parseInt(String(value), 10);
  return isNaN(n) ? fallback : n;
}

const REPORTS: Report[] = [
  // --- Matches ---
  {
    id: 'match-history',
    name: 'Match history',
    description: 'All matches filtered by status and opponent type',
    category: 'matches',
    params: [
      {
        name: 'status',
        type: 'select',
        default: 'all',
        options: ['all', 'active', 'completed', 'pending', 'cancelled'],
        label: 'Status',
      },
      {
        name: 'opponent',
        type: 'select',
        default: 'all',
        options: ['all', 'human', 'bot'],
        label: 'Opponent',
      },
      { name: 'limit', type: 'number', default: 50, label: 'Limit' },
    ],
    buildSql: (p) => {
      const status = safeSelect(
        p.status,
        ['all', 'active', 'completed', 'pending', 'cancelled'],
        'all',
      );
      const opponent = safeSelect(p.opponent, ['all', 'human', 'bot'], 'all');
      const limit = safeNumber(p.limit, 50);
      const statusClause = status === 'all' ? '' : `AND status = '${status}'`;
      const opponentClause =
        opponent === 'all'
          ? ''
          : opponent === 'bot'
            ? `AND bot_strategy IS NOT NULL`
            : `AND bot_strategy IS NULL`;
      return `SELECT id, player_1_name, player_2_name, bot_strategy, status, outcome, created_at FROM matches WHERE 1=1 ${statusClause} ${opponentClause} ORDER BY created_at DESC LIMIT ${limit}`;
    },
  },
  {
    id: 'victory-breakdown',
    name: 'Victory type breakdown',
    description: 'Count of completed matches grouped by victory type',
    category: 'matches',
    params: [],
    buildSql: () =>
      `SELECT outcome->>'victoryType' AS victory_type, COUNT(*)::int AS count FROM matches WHERE status = 'completed' AND outcome IS NOT NULL GROUP BY victory_type ORDER BY count DESC`,
  },
  {
    id: 'turn-distribution',
    name: 'Turn length distribution',
    description: 'Distribution of completed match lengths by turn count',
    category: 'matches',
    params: [],
    buildSql: () =>
      `SELECT jsonb_array_length(transaction_log) AS turns, COUNT(*)::int AS match_count FROM matches WHERE status = 'completed' GROUP BY turns ORDER BY turns ASC`,
  },
  {
    id: 'abandoned-matches',
    name: 'Cancelled / abandoned matches',
    description: 'Matches that were cancelled or never completed',
    category: 'matches',
    params: [{ name: 'limit', type: 'number', default: 50, label: 'Limit' }],
    buildSql: (p) => {
      const limit = safeNumber(p.limit, 50);
      return `SELECT id, player_1_name, player_2_name, status, created_at, updated_at FROM matches WHERE status IN ('cancelled', 'pending') ORDER BY created_at DESC LIMIT ${limit}`;
    },
  },
  // --- Players ---
  {
    id: 'win-loss-by-player',
    name: 'Win / loss by player',
    description: 'Win and loss counts for each user',
    category: 'players',
    params: [{ name: 'limit', type: 'number', default: 50, label: 'Limit' }],
    buildSql: (p) => {
      const limit = safeNumber(p.limit, 50);
      return `SELECT u.id, u.gamertag, u.elo, COUNT(CASE WHEN m.outcome->>'winnerId' = u.id::text THEN 1 END)::int AS wins, COUNT(CASE WHEN (m.player_1_id = u.id OR m.player_2_id = u.id) AND m.outcome->>'winnerId' != u.id::text AND m.outcome IS NOT NULL THEN 1 END)::int AS losses FROM users u LEFT JOIN matches m ON m.player_1_id = u.id OR m.player_2_id = u.id GROUP BY u.id, u.gamertag, u.elo ORDER BY wins DESC LIMIT ${limit}`;
    },
  },
  {
    id: 'elo-progression',
    name: 'Elo progression',
    description: 'Most recent Elo snapshots per user',
    category: 'players',
    params: [{ name: 'limit', type: 'number', default: 50, label: 'Limit' }],
    buildSql: (p) => {
      const limit = safeNumber(p.limit, 50);
      return `SELECT u.gamertag, s.category, s.elo, s.computed_at FROM elo_snapshots s JOIN users u ON u.id = s.user_id ORDER BY s.computed_at DESC LIMIT ${limit}`;
    },
  },
  {
    id: 'human-vs-bot',
    name: 'Human vs bot record',
    description: 'Win/loss record for human-vs-bot matches',
    category: 'players',
    params: [],
    buildSql: () =>
      `SELECT bot_strategy, COUNT(*)::int AS total, COUNT(CASE WHEN outcome->>'winnerId' = player_1_id::text THEN 1 END)::int AS human_wins, COUNT(CASE WHEN outcome->>'winnerId' = player_2_id::text THEN 1 END)::int AS bot_wins FROM matches WHERE bot_strategy IS NOT NULL AND status = 'completed' GROUP BY bot_strategy`,
  },
  // --- Integrity ---
  {
    id: 'turnhash-sweep',
    name: 'turnHash sweep',
    description: 'Matches where transaction_log entries are missing turnHash',
    category: 'integrity',
    params: [],
    buildSql: () =>
      `SELECT m.id, m.player_1_name, m.player_2_name, m.status, jsonb_array_length(m.transaction_log) AS total_turns, (SELECT COUNT(*)::int FROM jsonb_array_elements(m.transaction_log) AS e WHERE e->>'turnHash' IS NULL) AS missing_turn_hashes FROM matches m WHERE status = 'completed' AND jsonb_array_length(transaction_log) > 0 AND (SELECT COUNT(*) FROM jsonb_array_elements(m.transaction_log) AS e WHERE e->>'turnHash' IS NULL) > 0 ORDER BY missing_turn_hashes DESC`,
  },
  {
    id: 'fingerprint-audit',
    name: 'Fingerprint audit',
    description: 'Completed matches that have an event_log but no event_log_fingerprint',
    category: 'integrity',
    params: [],
    buildSql: () =>
      `SELECT id, player_1_name, player_2_name, created_at FROM matches WHERE status = 'completed' AND event_log IS NOT NULL AND event_log_fingerprint IS NULL ORDER BY created_at DESC`,
  },
  {
    id: 'missing-event-logs',
    name: 'Missing event logs',
    description: 'Completed matches with null event_log',
    category: 'integrity',
    params: [],
    buildSql: () =>
      `SELECT id, player_1_name, player_2_name, created_at FROM matches WHERE status = 'completed' AND event_log IS NULL ORDER BY created_at DESC`,
  },
];

export function registerReportRoutes(fastify: FastifyInstance) {
  // GET /admin-api/reports — list without buildSql
  fastify.get('/admin-api/reports', async (request, reply) => {
    const admin = await requireAdmin(request, reply);
    if (!admin) return;

    return reply.status(200).send(
      REPORTS.map(({ id, name, description, category, params }) => ({
        id,
        name,
        description,
        category,
        params,
      })),
    );
  });

  // GET /admin-api/reports/:reportId/sql — render SQL with query params
  fastify.get<{ Params: { reportId: string }; Querystring: Record<string, string> }>(
    '/admin-api/reports/:reportId/sql',
    async (request, reply) => {
      const admin = await requireAdmin(request, reply);
      if (!admin) return;

      const report = REPORTS.find((r) => r.id === request.params.reportId);
      if (!report) return reply.status(404).send({ error: 'Report not found', code: 'NOT_FOUND' });

      const renderedSql = report.buildSql(request.query ?? {});
      return reply.status(200).send({ sql: renderedSql });
    },
  );

  // POST /admin-api/reports/:reportId/run — run report
  fastify.post<{ Params: { reportId: string }; Body: unknown }>(
    '/admin-api/reports/:reportId/run',
    async (request, reply) => {
      const admin = await requireAdmin(request, reply);
      if (!admin) return;

      const report = REPORTS.find((r) => r.id === request.params.reportId);
      if (!report) return reply.status(404).send({ error: 'Report not found', code: 'NOT_FOUND' });

      const params = (request.body as Record<string, string | number>) ?? {};
      const renderedSql = report.buildSql(params);

      const start = Date.now();
      const rows = await db.execute(sql.raw(renderedSql));
      const durationMs = Date.now() - start;

      return reply.status(200).send({
        rows,
        rowCount: rows.length,
        durationMs,
        sql: renderedSql,
      });
    },
  );
}

import * as Sentry from '@sentry/browser';

export function trackClientEvent(
  event: string,
  attributes?: Record<string, string | number | boolean>,
): void {
  if (typeof Sentry.metrics?.count !== 'function') return;

  Sentry.metrics.count('client.event', 1, {
    attributes: {
      event,
      ...attributes,
    },
  });
}

import { render as preactRender } from 'preact';
import type {
  GridPosition,
  GameState,
  Card,
  CombatLogEntry,
  BattlefieldCard,
  Action,
  PlayerState,
} from '@phalanxduel/shared';
import type { AppState } from './state';
import { selectAttacker, selectDeployCard, clearSelection, toggleHelp } from './state';
import { getConnection } from './renderer';
import { HelpMarker } from './components/HelpMarker';
import { HealthBadge } from './components/HealthBadge';
import { CopyButton } from './components/CopyButton';
import { cardLabel, hpDisplay, suitColor, suitSymbol, isWeapon, isFace } from './cards';

const BONUS_LABELS: Record<string, string> = {
  aceInvulnerable: 'Ace invulnerable',
  aceVsAce: 'Ace vs Ace',
  diamondDoubleDefense: 'Diamond ×2 def',
  clubDoubleOverflow: 'Club ×2 overflow',
  spadeDoubleLp: 'Spade ×2 LP',
  heartDeathShield: 'Heart Shield',
};

function getPhaseLabel(gs: GameState): string {
  if (gs.phase === 'ReinforcementPhase') {
    return `Reinforce col ${(gs.reinforcement?.column ?? 0) + 1}`;
  } else if (gs.phase === 'DeploymentPhase') {
    return 'Deployment';
  }
  return gs.phase as string;
}

function getTurnIndicatorText(
  gs: GameState,
  isSpectator: boolean,
  myIdx: number,
): { text: string; isMyTurn: boolean } {
  const isMyTurn = gs.activePlayerIndex === myIdx;
  if (isSpectator) {
    const activeName =
      gs.players[gs.activePlayerIndex]?.player.name ?? `Player ${gs.activePlayerIndex + 1}`;
    return { text: `${activeName}'s turn`, isMyTurn: false };
  } else if (gs.phase === 'ReinforcementPhase') {
    return {
      text: isMyTurn ? 'Reinforce your column' : 'Opponent reinforcing',
      isMyTurn,
    };
  }
  return {
    text: isMyTurn ? 'Your turn' : "Opponent's turn",
    isMyTurn,
  };
}

function getBaseCellClasses(
  bCard: BattlefieldCard | null | undefined,
  isReinforcementCol: boolean,
) {
  const classes = ['bf-cell'];
  if (bCard) {
    classes.push('occupied');
    if (isFace(bCard.card)) classes.push('is-face');
    classes.push(`pz-aura-${bCard.card.suit}`);
  } else {
    classes.push('empty');
  }
  if (isReinforcementCol) classes.push('reinforce-col');
  return classes;
}

function getInteractionClasses(params: {
  bCard: BattlefieldCard | null | undefined;
  pos: GridPosition;
  isOpponent: boolean;
  gs: GameState;
  state: AppState;
  isMyTurn: boolean;
  isReinforcementCol: boolean;
}) {
  const { bCard, pos, isOpponent, gs, state, isMyTurn } = params;
  const classes: string[] = [];

  const isValidAttacker =
    !isOpponent &&
    bCard &&
    gs.phase === 'AttackPhase' &&
    isMyTurn &&
    pos.row === 0 &&
    isWeapon(bCard.card.suit);
  if (isValidAttacker) classes.push('pz-active-pulse');

  const isSelected =
    !isOpponent &&
    state.selectedAttacker?.row === pos.row &&
    state.selectedAttacker?.col === pos.col;
  if (isSelected) classes.push('selected');

  const { isTargetable, isDeployable, isReinforceable } = getTargetingStates(params);

  if (isTargetable || isDeployable || isReinforceable) classes.push('valid-target');

  return { classes, isTargetable, isDeployable, isReinforceable };
}

function getTargetingStates(params: {
  bCard: BattlefieldCard | null | undefined;
  pos: GridPosition;
  isOpponent: boolean;
  gs: GameState;
  state: AppState;
  isMyTurn: boolean;
  isReinforcementCol: boolean;
}) {
  const { bCard, pos, isOpponent, gs, state, isMyTurn, isReinforcementCol } = params;
  return {
    isTargetable:
      isOpponent && !!state.selectedAttacker && isMyTurn && pos.col === state.selectedAttacker.col,
    isDeployable:
      !isOpponent &&
      !bCard &&
      gs.phase === 'DeploymentPhase' &&
      isMyTurn &&
      !!state.selectedDeployCard,
    isReinforceable: isReinforcementCol && !bCard && !!state.selectedDeployCard,
  };
}

function getCellClasses(params: {
  bCard: BattlefieldCard | null | undefined;
  pos: GridPosition;
  isOpponent: boolean;
  gs: GameState;
  state: AppState;
  isMyTurn: boolean;
  isReinforcementCol: boolean;
}) {
  const { bCard, pos, isOpponent, state, isReinforcementCol } = params;
  const baseClasses = getBaseCellClasses(bCard, isReinforcementCol);
  const {
    classes: interClasses,
    isTargetable,
    isDeployable,
    isReinforceable,
  } = getInteractionClasses(params);

  return {
    className: [...baseClasses, ...interClasses].join(' '),
    isGhost: isOpponent && !bCard && pos.col === state.selectedAttacker?.col,
    isTargetable,
    isDeployable,
    isReinforceable,
  };
}

function BattlefieldCell({
  bCard,
  pos,
  isOpponent,
  gs,
  state,
}: {
  bCard: BattlefieldCard | null | undefined;
  pos: GridPosition;
  isOpponent: boolean;
  gs: GameState;
  state: AppState;
}) {
  const isMyTurn = gs.activePlayerIndex === (state.isSpectator ? 0 : state.playerIndex);
  const isReinforcementCol =
    !isOpponent && gs.phase === 'ReinforcementPhase' && pos.col === gs.reinforcement?.column;

  const { className, isGhost, isTargetable, isDeployable, isReinforceable } = getCellClasses({
    bCard,
    pos,
    isOpponent,
    gs,
    state,
    isMyTurn,
    isReinforcementCol,
  });

  const onClick = () => {
    if (isTargetable) {
      sendAttack(state, pos);
    } else if (!isOpponent && bCard && gs.phase === 'AttackPhase' && isMyTurn) {
      selectAttacker(pos);
    } else if (isDeployable && state.selectedDeployCard) {
      sendAction(state, {
        type: 'deploy',
        playerIndex: state.playerIndex ?? 0,
        column: pos.col,
        cardId: state.selectedDeployCard,
        timestamp: new Date().toISOString(),
      });
    } else if (isReinforceable && state.selectedDeployCard) {
      sendAction(state, {
        type: 'reinforce',
        playerIndex: state.playerIndex ?? 0,
        cardId: state.selectedDeployCard,
        timestamp: new Date().toISOString(),
      });
    }
  };

  return (
    <div
      class={className}
      style={
        isGhost
          ? { opacity: '0.3', borderColor: 'transparent' }
          : { borderColor: bCard ? suitColor(bCard.card.suit) : undefined }
      }
      data-testid={`${isOpponent ? 'opponent' : 'player'}-cell-r${pos.row}-c${pos.col}`}
      data-suit={bCard?.card.suit}
      onClick={onClick}
    >
      {bCard && <CellContent bCard={bCard} gs={gs} isOpponent={isOpponent} />}
    </div>
  );
}

function CellContent({
  bCard,
  gs,
  isOpponent,
}: {
  bCard: BattlefieldCard;
  gs: GameState;
  isOpponent: boolean;
}) {
  const color = suitColor(bCard.card.suit);
  return (
    <>
      <div class="card-rank" style={{ color }}>
        {bCard.card.face}
      </div>
      <div class="card-pip" style={{ color }}>
        {suitSymbol(bCard.card.suit)}
      </div>
      <div class="card-hp">{hpDisplay(bCard)}</div>
      <div class="card-type">{isWeapon(bCard.card.suit) ? 'ATK' : 'DEF'}</div>
      {!isOpponent &&
        gs.phase === 'AttackPhase' &&
        isWeapon(bCard.card.suit) &&
        (bCard.card.suit === 'spades' || bCard.card.suit === 'clubs') && (
          <div class="pz-multiplier">x2</div>
        )}
    </>
  );
}

function sendAttack(state: AppState, targetPos: GridPosition): void {
  if (!state.selectedAttacker || !state.matchId || state.playerIndex === null) return;
  getConnection()?.send({
    type: 'action',
    matchId: state.matchId,
    action: {
      type: 'attack',
      playerIndex: state.playerIndex,
      attackingColumn: state.selectedAttacker.col,
      defendingColumn: targetPos.col,
      timestamp: new Date().toISOString(),
    },
  });
}

function sendAction(state: AppState, action: Action): void {
  if (!state.matchId) return;
  getConnection()?.send({
    type: 'action',
    matchId: state.matchId,
    action,
  });
}

function Battlefield({
  gs,
  playerIdx,
  state,
  isOpponent,
}: {
  gs: GameState;
  playerIdx: number;
  state: AppState;
  isOpponent: boolean;
}) {
  const battlefield = gs.players[playerIdx]?.battlefield;
  if (!battlefield) return <div class="battlefield" />;

  const rows = gs.params?.rows ?? 2;
  const columns = gs.params?.columns ?? 4;

  const rowOrder = isOpponent
    ? Array.from({ length: rows }, (_, i) => rows - 1 - i)
    : Array.from({ length: rows }, (_, i) => i);

  return (
    <div class="battlefield" style={{ gridTemplateColumns: `repeat(${columns}, 1fr)` }}>
      {rowOrder.map((row) =>
        Array.from({ length: columns }, (_, col) => {
          const gridIdx = row * columns + col;
          const bCard = battlefield[gridIdx];
          const pos: GridPosition = { row, col };
          return (
            <BattlefieldCell
              key={`${row}-${col}`}
              bCard={bCard}
              pos={pos}
              isOpponent={isOpponent}
              gs={gs}
              state={state}
            />
          );
        }),
      )}
    </div>
  );
}

function Hand({ gs, state }: { gs: GameState; state: AppState }) {
  const myIdx = state.playerIndex ?? 0;
  const hand = gs.players[myIdx]?.hand ?? [];
  const isMyTurn = gs.activePlayerIndex === myIdx;

  return (
    <div class="hand-section">
      <div class="section-label">Your Hand</div>
      <HelpMarker helpKey="hand" />
      <div class="hand">
        {hand.map((card, i) => {
          let className = 'hand-card';
          if (isFace(card)) className += ' is-face';
          className += ` pz-aura-${card.suit}`;
          if (state.selectedDeployCard === card.id) className += ' selected';

          const isPlayable =
            (gs.phase === 'DeploymentPhase' || gs.phase === 'ReinforcementPhase') && isMyTurn;
          if (isPlayable) className += ' playable';
          if (gs.phase === 'ReinforcementPhase' && isMyTurn) className += ' reinforce-playable';

          return (
            <div
              key={card.id}
              class={className}
              style={{ borderColor: suitColor(card.suit) }}
              data-testid={`hand-card-${i}`}
              data-suit={card.suit}
              onClick={() => isPlayable && selectDeployCard(card.id)}
            >
              <div class="card-rank" style={{ color: suitColor(card.suit) }}>
                {card.face}
              </div>
              <div class="card-pip" style={{ color: suitColor(card.suit) }}>
                {suitSymbol(card.suit)}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function BattleLog({ gs }: { gs: GameState }) {
  const entries: CombatLogEntry[] = (gs.transactionLog ?? [])
    .filter((e) => e.details.type === 'attack')
    .map((e) => (e.details as { type: 'attack'; combat: CombatLogEntry }).combat);
  const recent = entries.slice(-8);

  if (recent.length === 0) return null;

  return (
    <div class="battle-log-section">
      <div class="section-label">Battle Log</div>
      <HelpMarker helpKey="log" />
      <div class="battle-log">
        {recent.map((entry, idx) => {
          const atkLabel = cardLabel(entry.attackerCard);
          return (
            <div key={idx} class="log-entry">
              T{entry.turnNumber}: {atkLabel} {'->'} Col {entry.targetColumn + 1}:
              {entry.steps.map((step, sIdx) => {
                const bonusText = (step.bonuses ?? []).map((b) => BONUS_LABELS[b] ?? b).join(', ');
                if (step.target === 'playerLp') {
                  return (
                    <span key={sIdx}>
                      {' '}
                      LP {step.lpBefore ?? '?'}
                      {'\u2192'}
                      {step.lpAfter ?? '?'} (-{step.damage}){bonusText && ` (${bonusText})`}
                    </span>
                  );
                } else {
                  const pos = step.target === 'frontCard' ? 'F' : 'B';
                  const stepCard = step.card ? cardLabel(step.card) : '?';
                  return (
                    <span key={sIdx}>
                      {' '}
                      {stepCard} [{pos} {step.hpBefore ?? '?'}
                      {'\u2192'}
                      {step.hpAfter ?? '?'}
                      {step.destroyed ? ' KO' : ''}] {bonusText && ` (${bonusText})`}
                    </span>
                  );
                }
              })}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function getBaseStats(ps: PlayerState | undefined) {
  const lp = ps?.lifepoints ?? 20;
  const handCount = ps?.handCount ?? ps?.hand.length ?? 0;
  const deckCount = ps?.drawpileCount ?? ps?.drawpile.length ?? 0;
  const gyCount = ps?.discardPileCount ?? ps?.discardPile.length ?? 0;
  return [
    { label: 'LP', value: String(lp) },
    { label: 'Hand', value: String(handCount).padStart(2, '0') },
    { label: 'Deck', value: String(deckCount).padStart(2, '0') },
    { label: 'GY', value: String(gyCount).padStart(2, '0') },
  ];
}

function StatsBlock({
  gs,
  playerIdx,
  isMine,
}: {
  gs: GameState;
  playerIdx: number;
  isMine: boolean;
}) {
  const ps = gs.players[playerIdx];
  const lastCard = ps?.discardPile.at(-1);
  const stats = getBaseStats(ps);

  if (isMine) stats.reverse();

  return (
    <div class={`stats-block ${isMine ? 'mine' : 'opponent'}`}>
      <HelpMarker helpKey="lp" />
      {!isMine && lastCard && <StatsLastCard card={lastCard} />}
      {stats.map((s, i) => (
        <div key={i} class="stats-row">
          <span class="stats-value">{s.value}</span>
          <span class="stats-label">{s.label}</span>
        </div>
      ))}
      {isMine && lastCard && <StatsLastCard card={lastCard} />}
    </div>
  );
}

function StatsLastCard({ card }: { card: Card }) {
  return (
    <div class="stats-row">
      <span class="stats-card-label" style={{ color: suitColor(card.suit) }}>
        {cardLabel(card)}
      </span>
      <span class="stats-label">last</span>
    </div>
  );
}

function StatsSidebar({ gs, state }: { gs: GameState; state: AppState }) {
  const myIdx = state.isSpectator ? 0 : (state.playerIndex ?? 0);
  const oppIdx = myIdx === 0 ? 1 : 0;
  const isMyTurn = gs.activePlayerIndex === myIdx;

  return (
    <div class="stats-sidebar">
      <HelpMarker helpKey="stats" />
      <StatsBlock gs={gs} playerIdx={oppIdx} isMine={false} />
      <hr class="stats-divider" />
      <div class="stats-turn-number">T{gs.turnNumber}</div>
      <div class={`stats-turn ${isMyTurn ? 'my-turn' : 'opp-turn'}`}>
        {isMyTurn ? 'YOUR TURN' : 'OPP'}
      </div>
      {state.spectatorCount > 0 && (
        <div class="spectator-count">{state.spectatorCount} watching</div>
      )}
      <hr class="stats-divider" />
      <StatsBlock gs={gs} playerIdx={myIdx} isMine={true} />
      <hr class="stats-divider" />
      <HealthBadge health={state.serverHealth} />
    </div>
  );
}

function InGameInvite({ matchId }: { matchId: string }) {
  return (
    <div class="in-game-invite">
      <span class="invite-label">Invite Spectators:</span>
      <div class="share-btn-row">
        <CopyButton label="Code" getValue={() => matchId} className="btn btn-tiny" />
        <CopyButton
          label="Link"
          getValue={() => {
            const url = new URL(window.location.href);
            url.searchParams.set('watch', matchId);
            return url.toString();
          }}
          className="btn btn-tiny"
        />
      </div>
    </div>
  );
}

function InfoBarActions({
  gs,
  state,
  myIdx,
  isMyTurn,
}: {
  gs: GameState;
  state: AppState;
  myIdx: number;
  isMyTurn: boolean;
}) {
  const isAttack = gs.phase === 'AttackPhase';
  const isReinforce = gs.phase === 'ReinforcementPhase';

  const onPass = () => {
    if (!state.matchId) return;
    getConnection()?.send({
      type: 'action',
      matchId: state.matchId,
      action: { type: 'pass', playerIndex: myIdx, timestamp: new Date().toISOString() },
    });
  };

  const onForfeit = () => {
    if (!state.matchId || !confirm('Are you sure you want to forfeit?')) return;
    getConnection()?.send({
      type: 'action',
      matchId: state.matchId,
      action: { type: 'forfeit', playerIndex: myIdx, timestamp: new Date().toISOString() },
    });
  };

  return (
    <>
      {isAttack && isMyTurn && state.selectedAttacker && (
        <button class="btn btn-small" data-testid="combat-cancel-btn" onClick={clearSelection}>
          Cancel
        </button>
      )}
      {isAttack && isMyTurn && (
        <button class="btn btn-small" data-testid="combat-pass-btn" onClick={onPass}>
          Pass
        </button>
      )}
      {(isAttack || isReinforce) && isMyTurn && (
        <button
          class="btn btn-small btn-forfeit"
          data-testid="combat-forfeit-btn"
          onClick={onForfeit}
        >
          Forfeit
        </button>
      )}
    </>
  );
}

function InfoBar({
  gs,
  state,
  myIdx,
  isSpectator,
  turnInfo,
}: {
  gs: GameState;
  state: AppState;
  myIdx: number;
  isSpectator: boolean;
  turnInfo: { text: string; isMyTurn: boolean };
}) {
  return (
    <div class="info-bar">
      <span class="phase" data-testid="phase-indicator">
        Phase: {getPhaseLabel(gs)} | Turn: {gs.turnNumber}
      </span>
      {isSpectator && <span class="spectator-badge">SPECTATING</span>}
      {gs.gameOptions?.damageMode === 'classic' && <span class="mode-tag">Per-Turn Reset</span>}
      <span
        class={`turn-indicator ${turnInfo.isMyTurn ? 'my-turn' : 'opp-turn'}`}
        data-testid="turn-indicator"
      >
        {turnInfo.text}
      </span>

      {!isSpectator && (
        <InfoBarActions gs={gs} state={state} myIdx={myIdx} isMyTurn={turnInfo.isMyTurn} />
      )}
      <button class="btn btn-small help-btn" onClick={toggleHelp}>
        {state.showHelp ? 'Exit Help' : 'Help ?'}
      </button>
    </div>
  );
}

function GameApp({ state }: { state: AppState }) {
  const gs = state.gameState;
  if (!gs) return null;

  const isSpectator = state.isSpectator;
  const myIdx = isSpectator ? 0 : (state.playerIndex ?? 0);
  const oppIdx = myIdx === 0 ? 1 : 0;

  const turnInfo = getTurnIndicatorText(gs, isSpectator, myIdx);

  return (
    <div class="game-layout" data-testid="game-layout">
      <div class="game-main">
        <div class="game">
          <div class="battlefield-section opponent">
            <div class="section-label">{gs.players[oppIdx]?.player.name ?? 'Opponent'}</div>
            <Battlefield gs={gs} playerIdx={oppIdx} state={state} isOpponent={true} />
            {!isSpectator && <HelpMarker helpKey="battlefield" />}
          </div>

          <InfoBar
            gs={gs}
            state={state}
            myIdx={myIdx}
            isSpectator={isSpectator}
            turnInfo={turnInfo}
          />

          <div class="battlefield-section mine">
            <div class="section-label">{gs.players[myIdx]?.player.name ?? 'You'}</div>
            <Battlefield gs={gs} playerIdx={myIdx} state={state} isOpponent={false} />
          </div>

          {!isSpectator && gs.players[myIdx] && <Hand gs={gs} state={state} />}
          <BattleLog gs={gs} />
          {!isSpectator && <InGameInvite matchId={state.matchId ?? ''} />}
        </div>
      </div>
      <StatsSidebar gs={gs} state={state} />
    </div>
  );
}

export function renderGamePreact(container: HTMLElement, state: AppState): void {
  preactRender(<GameApp state={state} />, container);
}

import type {
  GridPosition,
  GameState,
  Card,
  CombatLogEntry,
  BattlefieldCard,
} from '@phalanxduel/shared';
import type { AppState } from './state';
import { selectAttacker, selectDeployCard, clearSelection, getState, toggleHelp } from './state';
import { el, makeCopyBtn, getConnection, renderHealthBadge } from './renderer';
import { renderHelpMarker } from './help';
import { cardLabel, hpDisplay, suitColor, suitSymbol, isWeapon, isFace } from './cards';
import { applySuitAura } from './card-utils';

export function getPhaseLabel(gs: GameState): string {
  if (gs.phase === 'ReinforcementPhase') {
    return `Reinforce col ${(gs.reinforcement?.column ?? 0) + 1}`;
  } else if (gs.phase === 'DeploymentPhase') {
    return 'Deployment';
  }
  return gs.phase as string;
}

export function getTurnIndicatorText(
  gs: GameState,
  isSpectator: boolean,
  myIdx: number,
): { text: string; isMyTurn: boolean } {
  const isMyTurn = gs.activePlayerIndex === myIdx;
  if (isSpectator) {
    const activeName =
      gs.players[gs.activePlayerIndex]?.player.name ?? `Player ${gs.activePlayerIndex + 1}`;
    return { text: `${activeName}'s turn`, isMyTurn: false };
  } else if (gs.phase === 'ReinforcementPhase') {
    return {
      text: isMyTurn ? 'Reinforce your column' : 'Opponent reinforcing',
      isMyTurn,
    };
  }
  return {
    text: isMyTurn ? 'Your turn' : "Opponent's turn",
    isMyTurn,
  };
}

export interface ActionButtonDescriptor {
  label: string;
  testId?: string;
  className?: string;
}

export interface ActionButtonParams {
  gs: GameState;
  isSpectator: boolean;
  myIdx: number;
  selectedAttacker: GridPosition | null;
  showHelp: boolean;
}

export function getActionButtons(params: ActionButtonParams): ActionButtonDescriptor[] {
  const { gs, isSpectator, myIdx, selectedAttacker, showHelp } = params;
  const buttons: ActionButtonDescriptor[] = [];
  const isMyTurn = gs.activePlayerIndex === myIdx;

  if (!isSpectator && gs.phase === 'AttackPhase' && isMyTurn && selectedAttacker) {
    buttons.push({ label: 'Cancel', testId: 'combat-cancel-btn' });
  }

  if (!isSpectator && gs.phase === 'AttackPhase' && isMyTurn) {
    buttons.push({ label: 'Pass', testId: 'combat-pass-btn' });
  }

  if (
    !isSpectator &&
    (gs.phase === 'AttackPhase' || gs.phase === 'ReinforcementPhase') &&
    isMyTurn
  ) {
    buttons.push({ label: 'Forfeit', testId: 'combat-forfeit-btn', className: 'btn-forfeit' });
  }

  buttons.push({ label: showHelp ? 'Exit Help' : 'Help ?', className: 'help-btn' });

  return buttons;
}

export function createBattlefieldCell(
  bCard: BattlefieldCard | null | undefined,
  pos: GridPosition,
  isOpponent: boolean,
  gs: GameState,
): HTMLElement {
  const cell = el('div', 'bf-cell');
  cell.setAttribute(
    'data-testid',
    `${isOpponent ? 'opponent' : 'player'}-cell-r${pos.row}-c${pos.col}`,
  );

  if (bCard) {
    cell.classList.add('occupied');
    if (isFace(bCard.card)) cell.classList.add('is-face');
    cell.style.borderColor = suitColor(bCard.card.suit);

    applySuitAura(cell, bCard.card.suit);

    const rankEl = el('div', 'card-rank');
    rankEl.textContent = bCard.card.face;
    rankEl.style.color = suitColor(bCard.card.suit);
    cell.appendChild(rankEl);

    const suitEl = el('div', 'card-pip');
    suitEl.textContent = suitSymbol(bCard.card.suit);
    suitEl.style.color = suitColor(bCard.card.suit);
    cell.appendChild(suitEl);

    const hpEl = el('div', 'card-hp');
    hpEl.textContent = hpDisplay(bCard);
    cell.appendChild(hpEl);

    const typeEl = el('div', 'card-type');
    typeEl.textContent = isWeapon(bCard.card.suit) ? 'ATK' : 'DEF';
    cell.appendChild(typeEl);

    // Multiplier tag if active attacker
    if (!isOpponent && gs.phase === 'AttackPhase' && isWeapon(bCard.card.suit)) {
      if (bCard.card.suit === 'spades' || bCard.card.suit === 'clubs') {
        const tag = el('div', 'pz-multiplier');
        tag.textContent = 'x2';
        cell.appendChild(tag);
      }
    }
  } else {
    cell.classList.add('empty');
  }

  return cell;
}

export interface CellInteractionParams {
  cell: HTMLElement;
  bCard: BattlefieldCard | null | undefined;
  pos: GridPosition;
  gs: GameState;
  state: AppState;
  isOpponent: boolean;
}

export function attachCellInteraction(params: CellInteractionParams): void {
  const { cell, bCard, pos, gs, state, isOpponent } = params;
  if (bCard) {
    // Click handlers for occupied cells
    if (
      isOpponent &&
      state.selectedAttacker &&
      gs.activePlayerIndex === state.playerIndex &&
      pos.col === state.selectedAttacker.col
    ) {
      // Clicking opponent card in same column = target
      cell.classList.add('valid-target');
      cell.addEventListener('click', () => {
        sendAttack(state, pos);
      });
    } else if (
      !isOpponent &&
      gs.phase === 'AttackPhase' &&
      gs.activePlayerIndex === state.playerIndex
    ) {
      // ACTIVE COLUMN PULSE: if front row and can attack
      if (pos.row === 0 && isWeapon(bCard.card.suit)) {
        cell.classList.add('pz-active-pulse');
      }

      // Clicking my card = select attacker
      if (state.selectedAttacker?.row === pos.row && state.selectedAttacker?.col === pos.col) {
        cell.classList.add('selected');
      }
      cell.addEventListener('click', () => {
        selectAttacker(pos);
      });
    }
  } else {
    // Click handlers for empty cells

    // GHOST TARGETING: If I have an attacker selected, highlight empty cells in that column
    if (isOpponent && pos.col === state.selectedAttacker?.col) {
      cell.classList.add('valid-target');
      cell.style.opacity = '0.3';
      cell.addEventListener('click', () => {
        sendAttack(state, pos);
      });
    }

    // Deployment handling
    if (
      !isOpponent &&
      gs.phase === 'DeploymentPhase' &&
      gs.activePlayerIndex === state.playerIndex &&
      state.selectedDeployCard
    ) {
      cell.classList.add('valid-target');
      cell.addEventListener('click', () => {
        if (!state.matchId || state.playerIndex === null) return;
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: {
            type: 'deploy',
            playerIndex: state.playerIndex,
            column: pos.col,
            cardId: state.selectedDeployCard ?? '',
            timestamp: new Date().toISOString(),
          },
        });
      });
    }
  }
}

function sendAttack(state: AppState, targetPos: GridPosition): void {
  if (!state.selectedAttacker || !state.matchId || state.playerIndex === null) return;
  getConnection()?.send({
    type: 'action',
    matchId: state.matchId,
    action: {
      type: 'attack',
      playerIndex: state.playerIndex,
      attackingColumn: state.selectedAttacker.col,
      defendingColumn: targetPos.col,
      timestamp: new Date().toISOString(),
    },
  });
}

function getLifepoints(gs: GameState, playerIdx: number): number {
  return gs.players[playerIdx]?.lifepoints ?? 20;
}

function makeStatsRow(value: string, label: string): HTMLElement {
  const row = el('div', 'stats-row');
  const valEl = el('span', 'stats-value');
  valEl.textContent = value;
  row.appendChild(valEl);
  const labEl = el('span', 'stats-label');
  labEl.textContent = label;
  row.appendChild(labEl);
  return row;
}

function makeCardStatsRow(card: Card, label: string): HTMLElement {
  const row = el('div', 'stats-row');
  const valEl = el('span', 'stats-card-label');
  valEl.textContent = cardLabel(card);
  valEl.style.color = suitColor(card.suit);
  row.appendChild(valEl);
  const labEl = el('span', 'stats-label');
  labEl.textContent = label;
  row.appendChild(labEl);
  return row;
}

const BONUS_LABELS: Record<string, string> = {
  aceInvulnerable: 'Ace invulnerable',
  aceVsAce: 'Ace vs Ace',
  diamondDoubleDefense: 'Diamond \u00d72 def',
  clubDoubleOverflow: 'Club \u00d72 overflow',
  spadeDoubleLp: 'Spade \u00d72 LP',
  heartDeathShield: 'Heart Shield',
};

export function renderBattlefield(
  gs: GameState,
  playerIdx: number,
  state: AppState,
  isOpponent: boolean,
): HTMLElement {
  const grid = el('div', 'battlefield');
  const battlefield = gs.players[playerIdx]?.battlefield;
  if (!battlefield) return grid;

  const rows = gs.params?.rows ?? 2;
  const columns = gs.params?.columns ?? 4;
  grid.style.gridTemplateColumns = `repeat(${columns}, 1fr)`;

  // Render rows: for opponent, show back row first then front row so front faces center
  // For self, show front row first then back row
  const rowOrder = isOpponent
    ? Array.from({ length: rows }, (_, i) => rows - 1 - i)
    : Array.from({ length: rows }, (_, i) => i);

  for (const row of rowOrder) {
    for (let col = 0; col < columns; col++) {
      const gridIdx = row * columns + col;
      const bCard = battlefield[gridIdx];
      const pos: GridPosition = { row, col };

      const cell = createBattlefieldCell(bCard, pos, isOpponent, gs);

      // Highlight reinforcement column on my battlefield
      const isReinforcementCol =
        !isOpponent && gs.phase === 'ReinforcementPhase' && col === gs.reinforcement?.column;
      if (isReinforcementCol) {
        cell.classList.add('reinforce-col');
        if (state.selectedDeployCard) {
          cell.classList.add('valid-target');
          cell.addEventListener('click', () => {
            if (!state.matchId || state.playerIndex === null) return;
            getConnection()?.send({
              type: 'action',
              matchId: state.matchId,
              action: {
                type: 'reinforce',
                playerIndex: state.playerIndex,
                cardId: state.selectedDeployCard ?? '',
                timestamp: new Date().toISOString(),
              },
            });
          });
        }
      }

      attachCellInteraction({ cell, bCard, pos, gs, state, isOpponent });
      grid.appendChild(cell);
    }
  }

  return grid;
}

function renderHand(gs: GameState, state: AppState): HTMLElement {
  const handSection = el('div', 'hand-section');
  const label = el('div', 'section-label');
  label.textContent = 'Your Hand';
  handSection.appendChild(label);
  renderHelpMarker('hand', handSection);

  const handDiv = el('div', 'hand');
  const myIdx = state.playerIndex ?? 0;
  const hand = gs.players[myIdx]?.hand ?? [];
  const isMyTurn = gs.activePlayerIndex === myIdx;

  for (let i = 0; i < hand.length; i++) {
    const card = hand[i];
    if (!card) continue;

    const cardEl = el('div', 'hand-card');
    cardEl.setAttribute('data-testid', `hand-card-${i}`);
    if (isFace(card)) cardEl.classList.add('is-face');
    cardEl.style.borderColor = suitColor(card.suit);

    applySuitAura(cardEl, card.suit);

    const rankEl = el('div', 'card-rank');
    rankEl.textContent = card.face;
    rankEl.style.color = suitColor(card.suit);
    cardEl.appendChild(rankEl);

    const suitEl = el('div', 'card-pip');
    suitEl.textContent = suitSymbol(card.suit);
    suitEl.style.color = suitColor(card.suit);
    cardEl.appendChild(suitEl);

    if (gs.phase === 'DeploymentPhase' && isMyTurn) {
      cardEl.classList.add('playable');
      if (state.selectedDeployCard === card.id) {
        cardEl.classList.add('selected');
      }
      cardEl.addEventListener('click', () => {
        selectDeployCard(card.id);
      });
    }

    if (gs.phase === 'ReinforcementPhase' && isMyTurn) {
      cardEl.classList.add('playable', 'reinforce-playable');
      if (state.selectedDeployCard === card.id) {
        cardEl.classList.add('selected');
      }
      cardEl.addEventListener('click', () => {
        selectDeployCard(card.id); // Re-use selectDeployCard for reinforcement selection
      });
    }

    handDiv.appendChild(cardEl);
  }

  handSection.appendChild(handDiv);

  return handSection;
}

function renderBattleLog(gs: GameState): HTMLElement {
  const section = el('div', 'battle-log-section');
  const label = el('div', 'section-label');
  label.textContent = 'Battle Log';
  section.appendChild(label);
  renderHelpMarker('log', section);

  const logDiv = el('div', 'battle-log');
  const entries: CombatLogEntry[] = (gs.transactionLog ?? [])
    .filter((e) => e.details.type === 'attack')
    .map((e) => (e.details as { type: 'attack'; combat: CombatLogEntry }).combat);
  const recent = entries.slice(-8);

  for (const entry of recent) {
    const entryEl = el('div', 'log-entry');
    const atkLabel = cardLabel(entry.attackerCard);
    const parts: string[] = [`T${entry.turnNumber}: ${atkLabel} -> Col ${entry.targetColumn + 1}:`];

    for (const step of entry.steps) {
      if (step.target === 'playerLp') {
        let text = `LP ${step.lpBefore ?? '?'}\u2192${step.lpAfter ?? '?'} (-${step.damage})`;
        const bonusText = (step.bonuses ?? []).map((b) => BONUS_LABELS[b] ?? b).join(', ');
        if (bonusText) text += ` (${bonusText})`;
        parts.push(text);
      } else {
        const pos = step.target === 'frontCard' ? 'F' : 'B';
        const stepCard = step.card ? cardLabel(step.card) : '?';
        let text = `${stepCard} [${pos} ${step.hpBefore ?? '?'}\u2192${step.hpAfter ?? '?'}`;
        if (step.destroyed) text += ' KO';
        text += ']';
        const bonusText = (step.bonuses ?? []).map((b) => BONUS_LABELS[b] ?? b).join(', ');
        if (bonusText) text += ` (${bonusText})`;
        parts.push(text);
      }
    }

    entryEl.textContent = parts.join(' ');
    logDiv.appendChild(entryEl);
  }

  section.appendChild(logDiv);
  return section;
}

function renderStatsBlock(gs: GameState, playerIdx: number, isMine: boolean): HTMLElement {
  const ps = gs.players[playerIdx];
  const block = el('div', `stats-block ${isMine ? 'mine' : 'opponent'}`);
  renderHelpMarker('lp', block);

  const lp = getLifepoints(gs, playerIdx);
  const handCount = ps?.handCount ?? ps?.hand.length ?? 0;
  const deckCount = ps?.drawpileCount ?? ps?.drawpile.length ?? 0;
  const gyCount = ps?.discardPileCount ?? ps?.discardPile.length ?? 0;
  const lastCard = ps?.discardPile.at(-1);

  const stats = [
    { label: 'LP', value: String(lp) },
    { label: 'Hand', value: String(handCount).padStart(2, '0') },
    { label: 'Deck', value: String(deckCount).padStart(2, '0') },
    { label: 'GY', value: String(gyCount).padStart(2, '0') },
  ];

  if (isMine) {
    if (lastCard) block.appendChild(makeCardStatsRow(lastCard, 'last'));
    stats.reverse().forEach((s) => block.appendChild(makeStatsRow(s.value, s.label)));
  } else {
    stats.forEach((s) => block.appendChild(makeStatsRow(s.value, s.label)));
    if (lastCard) block.appendChild(makeCardStatsRow(lastCard, 'last'));
  }

  return block;
}

function renderStatsSidebar(
  gs: GameState,
  myIdx: number,
  oppIdx: number,
  spectatorCount: number,
): HTMLElement {
  const sidebar = el('div', 'stats-sidebar');
  const isMyTurn = gs.activePlayerIndex === myIdx;
  renderHelpMarker('stats', sidebar);

  sidebar.appendChild(renderStatsBlock(gs, oppIdx, false));
  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';

  const turnEl = el('div', 'stats-turn-number');
  turnEl.textContent = `T${gs.turnNumber}`;
  sidebar.appendChild(turnEl);

  const turnLabel = el('div', 'stats-turn');
  turnLabel.textContent = isMyTurn ? 'YOUR TURN' : 'OPP';
  turnLabel.classList.add(isMyTurn ? 'my-turn' : 'opp-turn');
  sidebar.appendChild(turnLabel);

  if (spectatorCount > 0) {
    const spectatorEl = el('div', 'spectator-count');
    spectatorEl.textContent = `${spectatorCount} watching`;
    sidebar.appendChild(spectatorEl);
  }

  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';
  sidebar.appendChild(renderStatsBlock(gs, myIdx, true));
  sidebar.appendChild(document.createElement('hr')).className = 'stats-divider';
  sidebar.appendChild(renderHealthBadge(getState().serverHealth));

  return sidebar;
}

function renderInGameInvite(state: AppState): HTMLElement {
  const section = el('div', 'in-game-invite');
  const label = el('span', 'invite-label');
  label.textContent = 'Invite Spectators:';
  section.appendChild(label);

  const btnRow = el('div', 'share-btn-row');

  const copyCode = makeCopyBtn('Code', () => state.matchId ?? '');
  copyCode.classList.add('btn-tiny');
  btnRow.appendChild(copyCode);

  const copyLink = makeCopyBtn('Link', () => {
    const url = new URL(window.location.href);
    url.searchParams.set('watch', state.matchId ?? '');
    return url.toString();
  });
  copyLink.classList.add('btn-tiny');
  btnRow.appendChild(copyLink);

  section.appendChild(btnRow);
  return section;
}

export function renderGame(container: HTMLElement, state: AppState): void {
  if (!state.gameState) return;
  if (!state.isSpectator && state.playerIndex === null) return;

  const gs = state.gameState;
  const isSpectator = state.isSpectator;
  const myIdx = isSpectator ? 0 : (state.playerIndex ?? 0);
  const oppIdx = myIdx === 0 ? 1 : 0;

  const layout = el('div', 'game-layout');
  layout.setAttribute('data-testid', 'game-layout');

  const main = el('div', 'game-main');
  const wrapper = el('div', 'game');

  // Opponent battlefield (top, mirrored)
  const oppSection = el('div', 'battlefield-section opponent');
  const oppLabel = el('div', 'section-label');
  oppLabel.textContent = gs.players[oppIdx]?.player.name ?? 'Opponent';
  oppSection.appendChild(oppLabel);
  oppSection.appendChild(renderBattlefield(gs, oppIdx, state, true));
  if (!isSpectator) renderHelpMarker('battlefield', oppSection);
  wrapper.appendChild(oppSection);

  // Info bar
  const infoBar = el('div', 'info-bar');
  const phaseText = el('span', 'phase');
  const phaseLabel = getPhaseLabel(gs);
  phaseText.textContent = `Phase: ${phaseLabel} | Turn: ${gs.turnNumber}`;
  phaseText.setAttribute('data-testid', 'phase-indicator');
  infoBar.appendChild(phaseText);

  if (isSpectator) {
    const spectatorBadge = el('span', 'spectator-badge');
    spectatorBadge.textContent = 'SPECTATING';
    infoBar.appendChild(spectatorBadge);
  }

  if (gs.gameOptions?.damageMode === 'classic') {
    const modeTag = el('span', 'mode-tag');
    modeTag.textContent = 'Per-Turn Reset';
    infoBar.appendChild(modeTag);
  }

  const turnText = el('span', 'turn-indicator');
  turnText.setAttribute('data-testid', 'turn-indicator');
  const turnInfo = getTurnIndicatorText(gs, isSpectator, myIdx);
  turnText.textContent = turnInfo.text;
  turnText.classList.add(turnInfo.isMyTurn ? 'my-turn' : 'opp-turn');
  infoBar.appendChild(turnText);

  const actionButtons = getActionButtons({
    gs,
    isSpectator,
    myIdx,
    selectedAttacker: state.selectedAttacker,
    showHelp: state.showHelp,
  });
  for (const btn of actionButtons) {
    const btnEl = el('button', `btn btn-small${btn.className ? ` ${btn.className}` : ''}`);
    btnEl.textContent = btn.label;
    if (btn.testId) btnEl.setAttribute('data-testid', btn.testId);
    if (btn.label === 'Cancel') {
      btnEl.addEventListener('click', clearSelection);
    } else if (btn.label === 'Pass') {
      btnEl.addEventListener('click', () => {
        if (!state.matchId) return;
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: {
            type: 'pass',
            playerIndex: myIdx,
            timestamp: new Date().toISOString(),
          },
        });
      });
    } else if (btn.label === 'Forfeit') {
      btnEl.addEventListener('click', () => {
        if (!state.matchId) return;
        if (!confirm('Are you sure you want to forfeit?')) return;
        getConnection()?.send({
          type: 'action',
          matchId: state.matchId,
          action: {
            type: 'forfeit',
            playerIndex: myIdx,
            timestamp: new Date().toISOString(),
          },
        });
      });
    } else if (btn.label === 'Help ?' || btn.label === 'Exit Help') {
      btnEl.addEventListener('click', toggleHelp);
    }
    infoBar.appendChild(btnEl);
  }

  wrapper.appendChild(infoBar);

  // My battlefield (bottom)
  const mySection = el('div', 'battlefield-section mine');
  const myLabel = el('div', 'section-label');
  myLabel.textContent = gs.players[myIdx]?.player.name ?? 'You';
  mySection.appendChild(myLabel);
  mySection.appendChild(renderBattlefield(gs, myIdx, state, false));
  wrapper.appendChild(mySection);

  if (!isSpectator && gs.players[myIdx]) {
    wrapper.appendChild(renderHand(gs, state));
  }

  // Battle log
  const hasAttacks = (gs.transactionLog ?? []).some((e) => e.details.type === 'attack');
  if (hasAttacks) {
    wrapper.appendChild(renderBattleLog(gs));
  }

  // Invite section (discrete)
  if (!isSpectator) {
    wrapper.appendChild(renderInGameInvite(state));
  }

  main.appendChild(wrapper);
  layout.appendChild(main);
  layout.appendChild(renderStatsSidebar(gs, myIdx, oppIdx, state.spectatorCount));
  container.appendChild(layout);
}

import type {
  PhalanxTurnResult,
  TransactionLogEntry,
  CombatLogEntry,
  CombatLogStep,
  CombatBonusType,
  GamePhase,
  Card,
  Suit,
} from '@phalanxduel/shared';
import { cardLabel } from './cards';
import type { NarrationBus, NarrationEntry } from './narration-bus';
import type { CardType } from './narration-bus';

// ── Timing Constants ─────────────────────────────

const DELAY_ATTACK = 800;
const DELAY_DESTROYED = 400;
const DELAY_OVERFLOW = 600;
const DELAY_DEPLOY = 600;
const DELAY_BONUS = 500;
const DELAY_PHASE = 400;

// ── Card Classification ──────────────────────────

function classifyCard(card: Card): CardType {
  if (card.type === 'ace') return 'ace';
  if (['jack', 'queen', 'king'].includes(card.type)) return 'face';
  return 'number';
}

// ── Card Lookup ─────────────────────────────────
// Card IDs are opaque — look up card data from game state instead of parsing IDs.

// ── Bonus Messages ───────────────────────────────

const BONUS_MESSAGES: Partial<Record<CombatBonusType, (card: string) => string>> = {
  aceInvulnerable: (card) => `${card} is invulnerable`,
  aceVsAce: (card) => `${card} breaks through invulnerability`,
  diamondDoubleDefense: () => '...halved by Diamond Defense',
  clubDoubleOverflow: () => '...doubled by Club Overflow',
  spadeDoubleLp: () => '...doubled by Spade direct strike',
};

// Bonuses that are suppressed (no narration)
const SUPPRESSED_BONUSES = new Set<CombatBonusType>([
  'faceCardIneligible',
  'heartDeathShield',
  'diamondDeathShield',
]);

/**
 * NarrationProducer — converts transaction log diffs into NarrationEntry sequences.
 *
 * Hooks into the game state update flow via onTurnResult. It diffs the transaction
 * log to find new entries, converts them to narration events with appropriate timing,
 * and enqueues them on the NarrationBus.
 */
export class NarrationProducer {
  private lastLogCount = 0;
  private lastPhase: GamePhase | null = null;
  private initialized = false;

  constructor(private readonly bus: NarrationBus) {}

  onTurnResult(result: PhalanxTurnResult): void {
    const { postState } = result;

    // Seed tracking on first call — prevents replaying history
    if (!this.initialized) {
      this.lastLogCount = postState.transactionLog?.length ?? 0;
      this.lastPhase = postState.phase;
      this.initialized = true;
      return;
    }

    const entries: NarrationEntry[] = [];

    // Phase change detection
    if (postState.phase !== this.lastPhase) {
      entries.push({
        event: { type: 'phase-change', phase: postState.phase },
        delayMs: DELAY_PHASE,
      });
      this.lastPhase = postState.phase;
    }

    // Diff transaction log
    const currentLogCount = postState.transactionLog?.length ?? 0;
    if (currentLogCount > this.lastLogCount) {
      const newTxEntries = postState.transactionLog?.slice(this.lastLogCount) ?? [];
      const columns = postState.params?.columns ?? 6;
      for (const txEntry of newTxEntries) {
        const produced = this.processTxEntry(txEntry, postState.players, columns);
        entries.push(...produced);
      }
      this.lastLogCount = currentLogCount;
    }

    if (entries.length > 0) {
      this.bus.enqueue(entries);
    }
  }

  private processTxEntry(
    txEntry: TransactionLogEntry,
    players: PhalanxTurnResult['postState']['players'],
    columns: number,
  ): NarrationEntry[] {
    const { action, details } = txEntry;

    // system:init has no playerIndex — skip it
    if (action.type === 'system:init') return [];

    const playerName = players[action.playerIndex]?.player.name ?? 'Unknown';

    switch (details.type) {
      case 'deploy':
        return this.processDeployEntry(playerName, action, {
          gridIndex: details.gridIndex,
          columns,
          players,
        });
      case 'pass':
        return this.processPassEntry(playerName, players);
      case 'attack':
        return this.processAttackEntry(details.combat, players);
      case 'reinforce':
      case 'forfeit':
        return [];
      default:
        return [];
    }
  }

  private processDeployEntry(
    playerName: string,
    action: TransactionLogEntry['action'],
    ctx: {
      gridIndex: number;
      columns: number;
      players: PhalanxTurnResult['postState']['players'];
    },
  ): NarrationEntry[] {
    if (action.type !== 'deploy') return [];

    // Look up the deployed card from the battlefield (post-state) instead of parsing the ID.
    const bfCard = ctx.players[action.playerIndex]?.battlefield[ctx.gridIndex];
    const cardObj = bfCard?.card;
    const card = cardObj ? cardLabel(cardObj) : 'card';
    const suit = cardObj?.suit ?? 'spades';
    const cardType = cardObj ? classifyCard(cardObj) : 'number';
    const column = ctx.gridIndex % ctx.columns;
    const row = Math.floor(ctx.gridIndex / ctx.columns);

    return [
      {
        event: {
          type: 'deploy',
          player: playerName,
          card,
          suit,
          cardType,
          column,
          row,
        },
        delayMs: DELAY_DEPLOY,
      },
    ];
  }

  private processPassEntry(
    _playerName: string,
    _players: PhalanxTurnResult['postState']['players'],
  ): NarrationEntry[] {
    // Pass is an internal turn-alternation mechanic, not a meaningful player action.
    // Suppress in all phases to keep narration focused on actual game events.
    return [];
  }

  private processAttackEntry(
    combat: CombatLogEntry,
    players: PhalanxTurnResult['postState']['players'],
  ): NarrationEntry[] {
    const entries: NarrationEntry[] = [];
    const defenderIdx = combat.attackerPlayerIndex === 0 ? 1 : 0;
    const defenderName = players[defenderIdx]?.player.name ?? 'Opponent';
    const attackerLabel = cardLabel(combat.attackerCard);
    const attackerSuit = combat.attackerCard.suit;
    const attackerCardType = classifyCard(combat.attackerCard);

    for (const step of combat.steps) {
      // Check for suppressed bonuses
      if (this.hasSuppressedBonusOnly(step)) continue;

      // Zero damage with no bonus — suppress entirely
      if (step.damage === 0 && !this.hasNarratableBonus(step)) continue;

      // Generate bonus callouts for zero-damage steps with bonuses
      if (step.damage === 0 && this.hasNarratableBonus(step)) {
        entries.push(...this.generateBonusEntries(step, attackerSuit));
        continue;
      }

      const targetSuit = step.card?.suit;
      const targetCardType = step.card ? classifyCard(step.card) : undefined;

      // Normal damage steps
      switch (step.target) {
        case 'frontCard':
        case 'backCard': {
          const targetLabel = step.card ? cardLabel(step.card) : 'card';

          if (step.target === 'backCard') {
            entries.push({
              event: {
                type: 'overflow',
                target: targetLabel,
                damage: step.damage,
                suit: targetSuit,
              },
              delayMs: DELAY_OVERFLOW,
            });
          } else {
            entries.push({
              event: {
                type: 'attack',
                attacker: attackerLabel,
                target: targetLabel,
                damage: step.damage,
                suit: attackerSuit,
                cardType: attackerCardType,
              },
              delayMs: DELAY_ATTACK,
            });
          }

          if (step.destroyed) {
            entries.push({
              event: {
                type: 'destroyed',
                card: targetLabel,
                suit: targetSuit,
                cardType: targetCardType,
              },
              delayMs: DELAY_DESTROYED,
            });
          }

          if (this.hasNarratableBonus(step)) {
            entries.push(...this.generateBonusEntries(step, attackerSuit));
          }
          break;
        }
        case 'playerLp': {
          entries.push({
            event: {
              type: 'lp-damage',
              player: defenderName,
              damage: step.damage,
              suit: attackerSuit,
            },
            delayMs: DELAY_ATTACK,
          });

          if (this.hasNarratableBonus(step)) {
            entries.push(...this.generateBonusEntries(step, attackerSuit));
          }
          break;
        }
      }
    }

    return entries;
  }

  private hasSuppressedBonusOnly(step: CombatLogStep): boolean {
    const bonuses = step.bonuses ?? [];
    if (bonuses.length === 0) return false;
    return bonuses.every((b) => SUPPRESSED_BONUSES.has(b));
  }

  private hasNarratableBonus(step: CombatLogStep): boolean {
    const bonuses = step.bonuses ?? [];
    return bonuses.some((b) => !SUPPRESSED_BONUSES.has(b) && BONUS_MESSAGES[b] !== undefined);
  }

  private generateBonusEntries(step: CombatLogStep, attackerSuit?: Suit): NarrationEntry[] {
    const bonuses = step.bonuses ?? [];
    const cardLbl = step.card ? cardLabel(step.card) : 'card';
    const stepSuit = step.card?.suit ?? attackerSuit;
    const stepCardType = step.card ? classifyCard(step.card) : undefined;
    const entries: NarrationEntry[] = [];

    for (const bonus of bonuses) {
      if (SUPPRESSED_BONUSES.has(bonus)) continue;
      const msgFn = BONUS_MESSAGES[bonus];
      if (!msgFn) continue;

      entries.push({
        event: {
          type: 'bonus',
          bonus,
          card: cardLbl,
          message: msgFn(cardLbl),
          suit: stepSuit,
          cardType: stepCardType,
        },
        delayMs: DELAY_BONUS,
      });
    }

    return entries;
  }
}

import type { PhalanxTurnResult, CombatLogEntry } from '@phalanxduel/shared';
import { getState } from './state';

/**
 * PizzazzEngine — event-driven animation overlay system.
 *
 * Reacts to game state diffs (phase changes, combat, victories) and renders
 * fixed-position overlays on document.body, outside #app, so they survive
 * the full-DOM-replacement render cycle.
 */
export class PizzazzEngine {
  private lastPhase: string | null = null;
  private lastLogCount = 0;
  private initialized = false;
  private reducedMotion: boolean;
  private activeAnimations = 0;

  constructor() {
    this.reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    this.syncIdleAttribute();
  }

  private trackAnimation(durationMs: number): void {
    this.activeAnimations++;
    this.syncIdleAttribute();
    setTimeout(() => {
      this.activeAnimations = Math.max(0, this.activeAnimations - 1);
      this.syncIdleAttribute();
    }, durationMs);
  }

  private syncIdleAttribute(): void {
    document.body.dataset.pzIdle = this.activeAnimations === 0 ? 'true' : 'false';
  }

  /** Main entry: receives the full PhalanxTurnResult from dispatch. */
  onTurnResult(result: PhalanxTurnResult): void {
    const { preState, postState } = result;

    // Seed tracking counters on first arrival to avoid replaying history
    if (!this.initialized) {
      this.lastPhase = postState.phase;
      this.lastLogCount = postState.transactionLog?.length ?? 0;
      this.initialized = true;
      return;
    }

    if (this.reducedMotion) return;

    // Phase tracking (phase splash now handled by NarrationOverlay)
    if (postState.phase !== this.lastPhase) {
      this.lastPhase = postState.phase;
    }

    // New combat log entries
    const currentLogCount = postState.transactionLog?.length ?? 0;
    if (currentLogCount > this.lastLogCount) {
      const newEntries = postState.transactionLog?.slice(this.lastLogCount) ?? [];
      for (const entry of newEntries) {
        if (entry.details.type === 'attack') {
          this.onCombat(entry.details.combat);
        }
      }
      this.lastLogCount = currentLogCount;
    }

    // Game over detection
    if (postState.phase === 'gameOver' && preState.phase !== 'gameOver') {
      this.onGameOver();
    }
  }

  // ── Splash (used for game over VICTORY/DEFEAT only) ──

  private showSplash(text: string, variant?: string): void {
    const overlay = this.makeEl('div', 'pz-splash-overlay');
    const splash = this.makeEl('div', 'pz-splash-text');
    if (variant) splash.classList.add(`pz-splash-${variant}`);
    splash.textContent = text;
    overlay.appendChild(splash);
    document.body.appendChild(overlay);

    this.trackAnimation(1600); // 1200ms display + 400ms exit
    setTimeout(() => {
      splash.classList.add('pz-exit');
      setTimeout(() => {
        overlay.remove();
      }, 400);
    }, 1200);
  }

  // ── Combat Effects ───────────────────────────────

  private onCombat(combat: CombatLogEntry): void {
    // Combat announcer replaced by NarrationOverlay

    if (combat.totalLpDamage > 0) {
      this.triggerScreenShake();
    }

    this.showDamagePops(combat);
  }

  private triggerScreenShake(): void {
    const app = document.getElementById('app');
    if (!app) return;
    app.classList.add('pz-screen-shake');
    this.trackAnimation(400);
    setTimeout(() => {
      app.classList.remove('pz-screen-shake');
    }, 400);
  }

  private showDamagePops(combat: CombatLogEntry): void {
    const playerIndex = getState().playerIndex;

    combat.steps
      .filter((s) => s.damage > 0)
      .forEach((step, idx) => {
        setTimeout(() => {
          const isLp = step.target === 'playerLp';
          let targetEl: Element | null = null;

          if (isLp) {
            const isAttackerMine = combat.attackerPlayerIndex === playerIndex;
            const selector = isAttackerMine ? '.stats-block.opponent' : '.stats-block.mine';
            targetEl = document.querySelector(selector);
          } else {
            const row = step.target === 'frontCard' ? 0 : 1;
            const isAttackerMine = combat.attackerPlayerIndex === playerIndex;
            const playerTag = isAttackerMine ? 'opponent' : 'player';
            targetEl = document.querySelector(
              `[data-testid="${playerTag}-cell-r${row}-c${combat.targetColumn}"]`,
            );
          }

          if (!targetEl) return;

          const rect = targetEl.getBoundingClientRect();
          const pop = this.makeEl('div', 'pz-damage-pop');
          if (step.bonuses?.length) pop.classList.add('pz-crit');
          pop.textContent = `-${step.damage}`;
          pop.style.left = `${rect.left + rect.width / 2}px`;
          pop.style.top = `${rect.top + rect.height / 2}px`;

          document.body.appendChild(pop);
          pop.addEventListener('animationend', () => {
            pop.remove();
          });

          // Hit flash on target element
          targetEl.classList.add('pz-hit-flash');
          if (isLp) targetEl.classList.add('pz-lp-flash');
          setTimeout(() => {
            targetEl?.classList.remove('pz-hit-flash', 'pz-lp-flash');
          }, 500);
          this.trackAnimation(idx * 300 + 500); // stagger + hit flash duration
        }, idx * 300); // Stagger steps
      });
  }

  // ── Game Over ────────────────────────────────────

  private onGameOver(): void {
    const gs = getState().gameState;
    const outcome = gs?.outcome;
    if (!outcome) return;

    const playerIndex = getState().playerIndex;
    const isWin = playerIndex !== null && outcome.winnerIndex === playerIndex;
    const text = isWin ? 'VICTORY' : 'DEFEAT';
    const variant = isWin ? 'victory' : 'defeat';

    // Delay so it follows the phase splash
    this.trackAnimation(1800 + 1600); // delay + splash duration
    setTimeout(() => {
      this.showSplash(text, variant);
    }, 1800);
  }

  // ── Helpers ──────────────────────────────────────

  private makeEl(tag: string, className: string): HTMLElement {
    const element = document.createElement(tag);
    element.className = className;
    return element;
  }
}

import { describe, it, expect, beforeEach, vi, afterEach } from 'vitest';
import type { ServerMessage, GameState } from '@phalanxduel/shared';

// Stub sessionStorage before importing state.ts
const store: Record<string, string> = {};
vi.stubGlobal('sessionStorage', {
  getItem: vi.fn((key: string) => store[key] ?? null),
  setItem: vi.fn((key: string, val: string) => {
    store[key] = val;
  }),
  removeItem: vi.fn((key: string) => {
    delete store[key];
  }),
});

import {
  getState,
  subscribe,
  dispatch,
  selectAttacker,
  selectDeployCard,
  clearSelection,
  setPlayerName,
  setDamageMode,
  setStartingLifepoints,
  setServerHealth,
  toggleHelp,
  clearError,
  resetToLobby,
  getSavedSession,
  onTurnResult,
} from '../src/state';

function makeGameState(phase = 'AttackPhase'): GameState {
  return {
    phase,
    turnNumber: 1,
    activePlayerIndex: 0,
    players: [],
    gameOptions: { damageMode: 'classic', startingLifepoints: 20 },
    transactionLog: [],
  } as unknown as GameState;
}

describe('state', () => {
  let unsubs: (() => void)[];

  beforeEach(() => {
    unsubs = [];
    resetToLobby();
    for (const key of Object.keys(store)) delete store[key];
    vi.clearAllMocks();
  });

  afterEach(() => {
    unsubs.forEach((fn) => {
      fn();
    });
  });

  describe('getState', () => {
    it('returns initial lobby state', () => {
      const s = getState();
      expect(s.screen).toBe('lobby');
      expect(s.matchId).toBeNull();
      expect(s.playerIndex).toBeNull();
      expect(s.gameState).toBeNull();
      expect(s.damageMode).toBe('classic');
      expect(s.startingLifepoints).toBe(20);
    });
  });

  describe('subscribe', () => {
    it('notifies listener on state change', () => {
      const listener = vi.fn();
      unsubs.push(subscribe(listener));
      setPlayerName('Alice');
      expect(listener).toHaveBeenCalledOnce();
      expect(listener.mock.calls[0]![0].playerName).toBe('Alice');
    });

    it('unsubscribe stops notifications', () => {
      const listener = vi.fn();
      const unsub = subscribe(listener);
      unsub();
      setPlayerName('Bob');
      expect(listener).not.toHaveBeenCalled();
    });
  });

  describe('dispatch matchCreated', () => {
    it('transitions to waiting screen and saves session', () => {
      setPlayerName('Alice');
      dispatch({
        type: 'matchCreated',
        matchId: 'm1',
        playerId: 'p1',
        playerIndex: 0,
      } as ServerMessage);

      const s = getState();
      expect(s.screen).toBe('waiting');
      expect(s.matchId).toBe('m1');
      expect(s.playerId).toBe('p1');
      expect(s.playerIndex).toBe(0);
      expect(sessionStorage.setItem).toHaveBeenCalled();
    });
  });

  describe('dispatch matchJoined', () => {
    it('sets match info and saves session', () => {
      dispatch({
        type: 'matchJoined',
        matchId: 'm2',
        playerId: 'p2',
        playerIndex: 1,
      } as ServerMessage);

      const s = getState();
      expect(s.matchId).toBe('m2');
      expect(s.playerIndex).toBe(1);
      expect(sessionStorage.setItem).toHaveBeenCalled();
    });
  });

  describe('dispatch spectatorJoined', () => {
    it('sets spectator mode and game screen', () => {
      dispatch({
        type: 'spectatorJoined',
        matchId: 'm3',
      } as ServerMessage);

      const s = getState();
      expect(s.screen).toBe('game');
      expect(s.isSpectator).toBe(true);
      expect(s.playerIndex).toBeNull();
    });
  });

  describe('dispatch gameState', () => {
    it('updates game screen for non-gameOver phase', () => {
      const gs = makeGameState('AttackPhase');
      dispatch({
        type: 'gameState',
        matchId: 'm1',
        result: {
          postState: gs,
          preState: gs,
          matchId: 'm1',
          playerId: 'p1',
          action: null,
          events: [],
        },
        spectatorCount: 3,
      } as unknown as ServerMessage);

      const s = getState();
      expect(s.screen).toBe('game');
      expect(s.gameState).toBe(gs);
      expect(s.spectatorCount).toBe(3);
      expect(s.selectedAttacker).toBeNull();
      expect(s.selectedDeployCard).toBeNull();
    });

    it('transitions to gameOver screen for gameOver phase', () => {
      const gs = makeGameState('gameOver');
      dispatch({
        type: 'gameState',
        matchId: 'm1',
        result: {
          postState: gs,
          preState: gs,
          matchId: 'm1',
          playerId: 'p1',
          action: null,
          events: [],
        },
      } as unknown as ServerMessage);

      expect(getState().screen).toBe('gameOver');
    });

    it('invokes turnResultCallback if registered', () => {
      const cb = vi.fn();
      onTurnResult(cb);
      const gs = makeGameState();
      const result = {
        postState: gs,
        preState: gs,
        matchId: 'm1',
        playerId: 'p1',
        action: null,
        events: [],
      };
      dispatch({
        type: 'gameState',
        matchId: 'm1',
        result,
      } as unknown as ServerMessage);

      expect(cb).toHaveBeenCalledWith(result);
    });
  });

  describe('dispatch errors', () => {
    it('actionError sets error', () => {
      dispatch({ type: 'actionError', error: 'bad move' } as ServerMessage);
      expect(getState().error).toBe('bad move');
    });

    it('matchError sets error', () => {
      dispatch({ type: 'matchError', error: 'match full' } as ServerMessage);
      expect(getState().error).toBe('match full');
    });

    it('opponentDisconnected sets error', () => {
      dispatch({ type: 'opponentDisconnected' } as ServerMessage);
      expect(getState().error).toContain('disconnected');
    });

    it('opponentReconnected clears error', () => {
      dispatch({ type: 'opponentDisconnected' } as ServerMessage);
      dispatch({ type: 'opponentReconnected' } as ServerMessage);
      expect(getState().error).toBeNull();
    });
  });

  describe('selection', () => {
    it('selectAttacker sets position and clears error', () => {
      dispatch({ type: 'actionError', error: 'oops' } as ServerMessage);
      selectAttacker({ row: 0, col: 2 });
      const s = getState();
      expect(s.selectedAttacker).toEqual({ row: 0, col: 2 });
      expect(s.error).toBeNull();
    });

    it('selectDeployCard sets cardId and clears error', () => {
      selectDeployCard('card-42');
      expect(getState().selectedDeployCard).toBe('card-42');
    });

    it('clearSelection resets both', () => {
      selectAttacker({ row: 0, col: 0 });
      selectDeployCard('card-1');
      clearSelection();
      const s = getState();
      expect(s.selectedAttacker).toBeNull();
      expect(s.selectedDeployCard).toBeNull();
    });
  });

  describe('settings', () => {
    it('setPlayerName updates name', () => {
      setPlayerName('Charlie');
      expect(getState().playerName).toBe('Charlie');
    });

    it('setDamageMode updates mode', () => {
      setDamageMode('cumulative');
      expect(getState().damageMode).toBe('cumulative');
    });

    it('setStartingLifepoints clamps to [1, 500]', () => {
      setStartingLifepoints(0);
      expect(getState().startingLifepoints).toBe(1);
      setStartingLifepoints(501);
      expect(getState().startingLifepoints).toBe(500);
      setStartingLifepoints(3.7);
      expect(getState().startingLifepoints).toBe(3);
      setStartingLifepoints(50);
      expect(getState().startingLifepoints).toBe(50);
    });

    it('setServerHealth updates health', () => {
      const health = { color: 'green' as const, label: 'Connected', hint: 'v1.0' };
      setServerHealth(health);
      expect(getState().serverHealth).toEqual(health);
    });

    it('toggleHelp flips showHelp', () => {
      expect(getState().showHelp).toBe(false);
      toggleHelp();
      expect(getState().showHelp).toBe(true);
      toggleHelp();
      expect(getState().showHelp).toBe(false);
    });

    it('clearError sets error to null', () => {
      dispatch({ type: 'actionError', error: 'err' } as ServerMessage);
      clearError();
      expect(getState().error).toBeNull();
    });
  });

  describe('session persistence', () => {
    it('getSavedSession returns null when empty', () => {
      expect(getSavedSession()).toBeNull();
    });

    it('getSavedSession returns stored session after matchCreated', () => {
      setPlayerName('Alice');
      dispatch({
        type: 'matchCreated',
        matchId: 'm1',
        playerId: 'p1',
        playerIndex: 0,
      } as ServerMessage);

      const stored = JSON.parse(store.phalanx_session!);
      expect(stored.matchId).toBe('m1');
      expect(stored.playerId).toBe('p1');
      expect(stored.playerName).toBe('Alice');
    });

    it('resetToLobby clears session', () => {
      dispatch({
        type: 'matchCreated',
        matchId: 'm1',
        playerId: 'p1',
        playerIndex: 0,
      } as ServerMessage);
      resetToLobby();
      expect(sessionStorage.removeItem).toHaveBeenCalledWith('phalanx_session');
      expect(getState().screen).toBe('lobby');
      expect(getState().matchId).toBeNull();
    });
  });
});

