                        properties: { min: { type: 'integer' }, max: { type: 'integer' } },
                      },
                      maxHandSize: {
                        type: 'object',
                        properties: {
                          min: { type: 'integer' },
                          note: { type: 'string' },
                        },
                      },
                      initialDraw: {
                        type: 'object',
                        properties: { note: { type: 'string' } },
                      },
                      startingLifepoints: {
                        type: 'object',
                        properties: { min: { type: 'integer' }, max: { type: 'integer' } },
                      },
                      totalSlots: {
                        type: 'object',
                        properties: { note: { type: 'string' } },
                      },
                    },
                  },
                  botStrategies: {
                    type: 'array',
                    items: { type: 'string' },
                  },
                },
              },
            },
          },
        },
      },
    },
    async (request, reply) =>
      traceHttpHandler('defaults', httpTraceContext(request, reply), () => ({
        ...DEFAULT_MATCH_PARAMS,
        startingLifepoints: 20,
        _meta: {
          configSource: 'shared/src/schema.ts → DEFAULT_MATCH_PARAMS',
          constraints: {
            rows: { min: 1, max: 12 },
            columns: { min: 1, max: 12 },
            maxHandSize: { min: 0, note: 'must be <= columns' },
            initialDraw: { note: 'rows * columns + columns' },
            startingLifepoints: { min: 1, max: 500 },
            totalSlots: { note: 'rows * columns <= 48' },
          },
          botStrategies: ['random', 'heuristic'],
        },
      })),
  );

  // ── POST /matches — create match via REST ────────────────────────
  app.post(
    '/matches',
    {
      schema: {
        tags: ['matches'],
        summary: 'Create a new match',
        response: {
          201: {
            type: 'object',
            properties: {
              matchId: { type: 'string', format: 'uuid' },
            },
          },
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('createMatch', httpTraceContext(request, reply), (span) => {
        const { matchId } = matchManager.createPendingMatch();
        span.setAttribute('match.id', matchId);
        matchesActive.add(1);

        void reply.status(201);
        return { matchId };
      });
    },
  );

  // ── GET /matches — public feed of active matches ─────────────────
  app.get(
    '/matches',
    {
      schema: {
        tags: ['matches'],
        summary: 'List all active matches',
        response: {
          200: {
            description: 'List of active matches with status summary',
            type: 'array',
            items: {
              type: 'object',
              properties: {
                matchId: { type: 'string', format: 'uuid' },
                players: {
                  type: 'array',
                  items: {
                    type: 'object',
                    properties: {
                      name: { type: 'string' },
                      connected: { type: 'boolean' },
                    },
                  },
                },
                spectatorCount: { type: 'integer' },
                phase: { type: 'string', nullable: true },
                turnNumber: { type: 'integer', nullable: true },
                ageSeconds: { type: 'integer' },
                lastActivitySeconds: { type: 'integer' },
              },
            },
          },
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('listMatches', httpTraceContext(request, reply), () => {
        const now = Date.now();
        const feed = [...matchManager.matches.values()].map((m) => ({
          matchId: m.matchId,
          players: m.players
            .map((p) => (p ? { name: p.playerName, connected: p.socket?.readyState === 1 } : null))
            .filter(Boolean),
          spectatorCount: m.spectators.length,
          phase: m.state?.phase ?? null,
          turnNumber: m.state?.turnNumber ?? null,
          ageSeconds: Math.floor((now - m.createdAt) / 1000),
          lastActivitySeconds: Math.floor((now - m.lastActivityAt) / 1000),
        }));
        return feed;
      });
    },
  );

  // ── GET /matches/:matchId/replay — replay and validate a match ──
  app.get<{ Params: { matchId: string } }>(
    '/matches/:matchId/replay',
    {
      schema: {
        tags: ['matches'],
        summary: 'Replay and validate a match from its action history',
        params: {
          type: 'object',
          properties: {
            matchId: { type: 'string', format: 'uuid' },
          },
          required: ['matchId'],
        },
        response: {
          200: {
            type: 'object',
            properties: {
              valid: { type: 'boolean' },
              actionCount: { type: 'integer' },
              finalStateHash: { type: 'string' },
              error: { type: 'string' },
              failedAtIndex: { type: 'integer' },
            },
          },
          401: {
            type: 'object',
            properties: {
              error: { type: 'string' },
              code: { type: 'string' },
            },
          },
          404: {
            type: 'object',
            properties: {
              error: { type: 'string' },
              code: { type: 'string' },
            },
          },
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('replayMatch', httpTraceContext(request, reply), async () => {
        if (!checkBasicAuth(request.headers.authorization)) {
          void reply.status(401).header('WWW-Authenticate', 'Basic realm="Phalanx Duel Admin"');
          return { error: 'Unauthorized', code: 'UNAUTHORIZED' };
        }

        const { matchId } = request.params;
        const match = await matchManager.getMatch(matchId);
        if (!match?.config) {
          void reply.status(404);
          return { error: 'Match not found', code: 'MATCH_NOT_FOUND' };
        }

        const result = replayGame(match.config, match.actionHistory, {
          hashFn: computeStateHash,
        });

        return {
          valid: result.valid,
          actionCount: match.actionHistory.length,
          finalStateHash: computeStateHash(result.finalState),
          ...(result.error ? { error: result.error, failedAtIndex: result.failedAtIndex } : {}),
        };
      });
    },
  );

  // ── GET /admin/ab-tests — Basic Auth JSON A/B config snapshot ────
  app.get(
    '/admin/ab-tests',
    {
      schema: {
        hide: true,
        response: {
          200: {
            type: 'object',
            properties: {
              tests: {
                type: 'array',
                items: {
                  type: 'object',
                  properties: {
                    id: { type: 'string' },
                    description: { type: 'string', nullable: true },
                    variants: {
                      type: 'array',
                      items: {
                        type: 'object',
                        properties: {
                          name: { type: 'string' },
                          ratio: { type: 'number' },
                        },
                        required: ['name', 'ratio'],
                      },
                    },
                    totalRatio: { type: 'number' },
                  },
                  required: ['id', 'description', 'variants', 'totalRatio'],
                },
              },
              warnings: {
                type: 'array',
                items: { type: 'string' },
              },
            },
            required: ['tests', 'warnings'],
          },
          401: {
            type: 'object',
            properties: {
              error: { type: 'string' },
              code: { type: 'string' },
            },
            required: ['error', 'code'],
          },
        },
      },
    },
    async (request, reply) => {
      return traceHttpHandler('admin.abTests', httpTraceContext(request, reply), () => {
        if (!checkBasicAuth(request.headers.authorization)) {
          void reply.status(401).header('WWW-Authenticate', 'Basic realm="Phalanx Duel Admin"');
          return { error: 'Unauthorized', code: 'UNAUTHORIZED' };
        }

        return getAbTestsSnapshotFromEnv();
      });
    },
  );

  // ── GET /admin — Basic Auth HTML admin dashboard ─────────────────
  app.get(
    '/admin',
    {
      schema: {
        hide: true,
      },
    },
    async (request, reply) => {
      return traceHttpHandler('admin.dashboard', httpTraceContext(request, reply), () => {
        if (!checkBasicAuth(request.headers.authorization)) {
          void reply
            .status(401)
            .header('WWW-Authenticate', 'Basic realm="Phalanx Duel Admin"')
            .header('Content-Type', 'text/html');
          return '<p>Unauthorized</p>';
        }
        void reply.header('Content-Type', 'text/html');
        return renderAdminDashboard();
      });
    },
  );

  const allowDebugErrorRoute =
    (process.env.NODE_ENV ?? 'development') === 'development' ||
    process.env.NODE_ENV === 'test' ||
    process.env.PHALANX_ENABLE_DEBUG_ERROR_ROUTE === '1';
  if (allowDebugErrorRoute) {
    // ── GET /debug/error — trigger a server error for Sentry validation ──
    app.get('/debug/error', { schema: { hide: true } }, async (request, reply) =>
      traceHttpHandler('debug.error', httpTraceContext(request, reply), () => {
        Sentry.logger.info('User triggered test error', { action: 'test_error_endpoint' });
        testCounter.add(1);
        throw new Error('Sentry Validation Error: Server-side trigger successful');
      }),
    );
  }

  // ── WebSocket routing ────────────────────────────────────────────
  const wsConnectionsByIp = new Map<string, number>();
  const MAX_WS_PER_IP = 10;

  app.register(async (fastify) => {
    fastify.get('/ws', { websocket: true }, async (socket, req) => {
      const clientIp = req.ip;

      // 0. Connection Limiting by IP (OWASP: DoS Prevention)
      const currentCount = wsConnectionsByIp.get(clientIp) ?? 0;
      if (currentCount >= MAX_WS_PER_IP) {
        app.log.warn({ clientIp }, 'WebSocket connection rejected: Too many connections from IP');
        socket.close(1008, 'Too many connections from this IP');
        return;
      }
      wsConnectionsByIp.set(clientIp, currentCount + 1);

      // 1. Optional Authentication
      let authUser: { id: string; name: string } | null = null;
      try {
        const token =
          req.cookies.phalanx_refresh ??
          req.cookies.token ??
          req.headers.authorization?.replace('Bearer ', '');
        if (token) {
          const p = fastify.jwt.verify<{
            id: string;
            gamertag: string;
            suffix: number;
            name?: string;
          }>(token);
          authUser = {
            id: p.id,
            name: p.name ?? `${p.gamertag}#${String(p.suffix).padStart(4, '0')}`,
          };
        }
      } catch {
        // Auth is optional for now, so we just continue as guest
      }

      // 2. Origin Validation (OWASP: CSWSH Protection)
      const origin = req.headers.origin;
      const allowedOrigins = [
        'https://phalanxduel.fly.dev',
        'https://phalanxduel-staging.fly.dev',
        'https://play.phalanxduel.com',
        'https://phalanxduel.com',
        'http://localhost:3001',
        'http://localhost:5173', // Vite dev server
        'http://127.0.0.1:5173', // Vite dev server (IP)
      ];

      const isTest = (process.env.NODE_ENV ?? 'development') === 'test';
      if (!origin && !isTest) {
        app.log.warn({ clientIp }, 'WebSocket connection rejected: Missing Origin');
        socket.close(1008, 'Origin required');
        return;
      }

      if (origin && !allowedOrigins.includes(origin)) {
        app.log.warn({ origin, clientIp }, 'WebSocket connection rejected: Invalid Origin');
        socket.close(1008, 'Invalid Origin');
        return;
      }

      void trackProcess('ws.connection', {}, () => {
        wsConnections.add(1);

        // 3. Heartbeat (OWASP: Connection Management)
        let isAlive = true;
        socket.on('pong', () => {
          isAlive = true;
        });

        const pingInterval = setInterval(() => {
          if (!isAlive) {
            app.log.info({ clientIp }, 'Closing dead WebSocket connection (no pong)');
            socket.terminate();
            return;
          }
          isAlive = false;
          socket.ping();
        }, 30_000);

        // Rate limiting: 10 messages per second sliding window
        const MSG_LIMIT = 10;
        const WINDOW_MS = 1000;
        const timestamps: number[] = [];

        function sendMessage(msg: ServerMessage): void {
          if (socket.readyState === 1) {
            socket.send(JSON.stringify(msg));
          }
        }

        socket.on('message', (raw: RawData) => {
          // 4. Payload size limit (10KB) (OWASP: DoS Prevention)
          const size = Array.isArray(raw)
            ? raw.reduce((acc, b) => acc + b.length, 0)
            : raw instanceof ArrayBuffer
              ? raw.byteLength
              : raw.length;

          if (size > 10240) {
            app.log.warn({ size, clientIp }, 'WebSocket message rejected: Payload too large');
            socket.close(1009, 'Message too large');
            return;
          }

          // Rate limit check
          const now = Date.now();
          while (timestamps.length > 0 && (timestamps[0] ?? 0) <= now - WINDOW_MS) {
            timestamps.shift();
          }
          if (timestamps.length >= MSG_LIMIT) {
            sendMessage({ type: 'matchError', error: 'Too many messages', code: 'RATE_LIMITED' });
            return;
          }
          timestamps.push(now);
          const messageStr = typeof raw === 'string' ? raw : raw.toString();

          let parsed: unknown;
          try {
            parsed = JSON.parse(messageStr);
          } catch {
            sendMessage({ type: 'matchError', error: 'Invalid JSON', code: 'PARSE_ERROR' });
            return;
          }

          const result = ClientMessageSchema.safeParse(parsed);
          if (!result.success) {
            app.log.error(
              { errors: result.error.issues, parsed, clientIp },
              'Invalid Client Message',
            );
            sendMessage({
              type: 'matchError',
              error: 'Invalid message format',
              code: 'VALIDATION_ERROR',
            });
            return;
          }

          const msg = result.data;

          switch (msg.type) {
            case 'createMatch': {
              void traceWsMessage('createMatch', {}, (span) => {
                try {
                  const resolvedSeed = resolveCreateMatchSeed(msg);
                  if (process.env.NODE_ENV === 'production' && resolvedSeed !== undefined) {
                    throw new MatchError(
                      'rngSeed is not allowed in production',
                      'SEED_NOT_ALLOWED',
                    );
                  }

                  const gameOptions = msg.gameOptions
                    ? {
                        damageMode: msg.gameOptions.damageMode,
                        startingLifepoints: msg.gameOptions.startingLifepoints,
                        classicDeployment: msg.gameOptions.classicDeployment,
                        // quickStart is stripped in production to prevent abuse
                        quickStart:
                          process.env.NODE_ENV === 'production'
                            ? undefined
                            : msg.gameOptions.quickStart,
                      }
                    : undefined;
                  const botOptions =
                    msg.opponent === 'bot-random' || msg.opponent === 'bot-heuristic'
                      ? {
                          opponent: msg.opponent,
                          botConfig: {
                            strategy:
                              msg.opponent === 'bot-heuristic'
                                ? ('heuristic' as const)
                                : ('random' as const),
                            seed: Date.now(),
                          },
                        }
                      : undefined;
                  const { matchId, playerId, playerIndex } = matchManager.createMatch(
                    authUser?.name ?? msg.playerName,
                    socket,
                    {
                      gameOptions,
                      rngSeed: resolvedSeed,
                      botOptions,
                      matchParams: msg.matchParams,
                      userId: authUser?.id,
                      creatorIp: clientIp,
                    },
                  );
                  span.setAttribute('match.id', matchId);
                  matchesActive.add(1);
                  sendMessage({ type: 'matchCreated', matchId, playerId, playerIndex });
                  // For bot matches the game is already initialized;
                  // broadcast state after matchCreated so the client sets playerIndex first.
                  if (botOptions) {
                    matchManager.broadcastMatchState(matchId);
                  }
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'CREATE_FAILED' });
                  }
                }
              });
              break;
            }

            case 'joinMatch': {
              void traceWsMessage('joinMatch', { 'match.id': msg.matchId }, async (span) => {
                try {
                  const { playerId, playerIndex } = await matchManager.joinMatch(
                    msg.matchId,
                    authUser?.name ?? msg.playerName,
                    socket,
                    authUser?.id,
                  );
                  span.setAttribute('player.id', playerId);
                  // Send matchJoined to joining player BEFORE broadcasting state
                  sendMessage({
                    type: 'matchJoined',
                    matchId: msg.matchId,
                    playerId,
                    playerIndex,
                  });
                  matchManager.broadcastMatchState(msg.matchId);
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'JOIN_FAILED' });
                  }
                }
              });
              break;
            }

            case 'rejoinMatch': {
              void traceWsMessage('rejoinMatch', { 'match.id': msg.matchId }, async (span) => {
                try {
                  const { playerIndex } = await matchManager.rejoinMatch(
                    msg.matchId,
                    msg.playerId,
                    socket,
                  );
                  span.setAttribute('player.id', msg.playerId);
                  sendMessage({
                    type: 'matchJoined',
                    matchId: msg.matchId,
                    playerId: msg.playerId,
                    playerIndex,
                  });
                  matchManager.broadcastMatchState(msg.matchId);
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'REJOIN_FAILED' });
                  }
                }
              });
              break;
            }

            case 'watchMatch': {
              void traceWsMessage('watchMatch', { 'match.id': msg.matchId }, async (span) => {
                try {
                  const { spectatorId } = await matchManager.watchMatch(msg.matchId, socket);
                  span.setAttribute('spectator.id', spectatorId);
                  sendMessage({ type: 'spectatorJoined', matchId: msg.matchId, spectatorId });
                  // Broadcast state after sending spectatorJoined so client sets isSpectator first
                  matchManager.broadcastMatchState(msg.matchId);
                } catch (err) {
                  if (err instanceof MatchError) {
                    sendMessage({ type: 'matchError', error: err.message, code: err.code });
                  } else {
                    const error = err instanceof Error ? err.message : 'Unknown error';
                    sendMessage({ type: 'matchError', error, code: 'WATCH_FAILED' });
                  }
                }
              });
              break;
            }

            case 'authenticate': {
              try {
                const authPayload = fastify.jwt.verify<{
                  id: string;
                  gamertag: string;
                  suffix: number;
                }>(msg.token);
                const displayName = formatGamertag(authPayload.gamertag, authPayload.suffix);
                authUser = { id: authPayload.id, name: displayName };
                matchManager.updatePlayerIdentity(socket, authPayload.id, displayName);
                sendMessage({
                  type: 'authenticated',
                  user: { id: authPayload.id, name: displayName, elo: 0 },
                });
              } catch {
                sendMessage({ type: 'auth_error', error: 'Invalid token' });
              }
              break;
            }

            case 'action': {
              const socketInfo = matchManager.socketMap.get(socket);
              if (!socketInfo || socketInfo.isSpectator) {
                sendMessage({
                  type: 'matchError',
                  error: 'Not connected to a match',
                  code: 'NOT_IN_MATCH',
                });
                return;
              }

              traceWsMessage(
                'action',
                {
                  'match.id': msg.matchId,
                  'player.id': socketInfo.playerId,
                  'action.type': msg.action.type,
                },
                async (_span) => {
                  await trackProcess(
                    'game.action',
                    {
                      'action.type': msg.action.type,
                      'match.id': msg.matchId,
                    },
                    async () => {
                      const start = performance.now();

                      try {
                        await matchManager.handleAction(
                          msg.matchId,
                          socketInfo.playerId,
                          msg.action,
                        );
                        actionsTotal.add(1, { 'action.type': msg.action.type });
                        actionsDurationMs.record(performance.now() - start);

                        // Emit the transaction log entry to the Pino log stream so the
                        // game can be tailed in real-time: tail -f logs/server.log | jq .
                        const txEntry = matchManager.matches
                          .get(msg.matchId)
                          ?.state?.transactionLog?.at(-1);
                        if (txEntry) {
                          const loggedDetails =
                            txEntry.action.type === 'deploy' && txEntry.details.type === 'pass'
                              ? { ...txEntry.details, type: 'deploy' as const }
                              : txEntry.details;
                          app.log.info(
                            {
                              event: 'game_action',
                              matchId: msg.matchId,
                              playerId: socketInfo.playerId,
                              turn: txEntry.sequenceNumber,
                              action: txEntry.action.type,
                              details: loggedDetails,
                              stateHash: txEntry.stateHashAfter,
                            },
                            `game:${txEntry.action.type} t${txEntry.sequenceNumber}`,
                          );
                        }
                      } catch (err) {
                        actionsDurationMs.record(performance.now() - start);
                        if (err instanceof ActionError) {
                          sendMessage({
                            type: 'actionError',
                            error: err.message,
                            code: err.code,
                          });
                        } else if (err instanceof MatchError) {
                          sendMessage({ type: 'matchError', error: err.message, code: err.code });
                        } else {
                          const error = err instanceof Error ? err.message : 'Unknown error';
                          sendMessage({
                            type: 'actionError',
                            error,
                            code: 'ACTION_FAILED',
                          });
                        }
                        throw err; // Re-throw so trackProcess records the error
                      }
                    },
                  );
                },
              ).catch(() => {
                // Errors are already sent as WebSocket messages (line 943-956)
                // and recorded on OTel spans via re-throw through withActiveSpan.
                // Swallow the final rejection to prevent unhandled promise rejection.
              });
              break;
            }
          }
        });

        socket.on('close', () => {
          clearInterval(pingInterval);
          wsConnections.add(-1);
          matchManager.handleDisconnect(socket);

          // Decrement IP-based connection counter
          const count = wsConnectionsByIp.get(clientIp) ?? 1;
          if (count <= 1) {
            wsConnectionsByIp.delete(clientIp);
          } else {
            wsConnectionsByIp.set(clientIp, count - 1);
          }

          app.log.info({ clientIp }, 'WebSocket client disconnected');
        });
      });
    });
  });

  // Match cleanup: remove stale matches every 60 seconds
  matchManager.onMatchRemoved = () => {
    matchesActive.add(-1);
  };
  const cleanupInterval = setInterval(() => {
    void trackProcess('match.cleanup', {}, () => {
      const removed = matchManager.cleanupMatches();
      if (removed > 0) {
        app.log.info({ removed }, 'Cleaned up stale matches');
      }
    });
  }, 60_000);
  app.addHook('onClose', () => {
    clearInterval(cleanupInterval);
  });

  // Expose matchManager for testing
  app.decorate('matchManager', matchManager);

  return app;
}

import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { drizzle } from 'drizzle-orm/postgres-js';
import { migrate } from 'drizzle-orm/postgres-js/migrator';
import postgres from 'postgres';
import '../loadEnv.js';

const connectionString = process.env.DATABASE_URL;

if (!connectionString) {
  console.error('DATABASE_URL is not set');
  process.exit(1);
}

// Resolve drizzle/ relative to the server package root, not CWD.
// In dev: server/src/db/migrate.ts → ../../drizzle
// In prod: server/dist/db/migrate.js → ../../drizzle
const __dirname = dirname(fileURLToPath(import.meta.url));
const migrationsFolder = resolve(__dirname, '../../drizzle');

const sql = postgres(connectionString, { max: 1 });
const db = drizzle(sql);

async function main() {
  console.log(`Running migrations from ${migrationsFolder}...`);
  await migrate(db, { migrationsFolder });
  console.log('Migrations complete!');
  await sql.end();
}

main().catch((err) => {
  console.error('Migration failed:', err);
  process.exit(1);
});

import './instrument.js';
import { buildApp } from './app.js';
import { checkPendingMigrations } from './db/check-migrations.js';

async function main(): Promise<void> {
  await checkPendingMigrations();
  const app = await buildApp();
  const port = parseInt(process.env.PHALANX_SERVER_PORT ?? '3001', 10);
  const host = process.env.HOST ?? '0.0.0.0';

  await app.listen({ port, host });
  console.log(`Phalanx Duel server listening on http://${host}:${port}`);

  // ── Graceful Shutdown Handler ────────────────────────────────────
  // When the container receives SIGTERM (Kubernetes, Docker stop, Fly.io deploy),
  // close the server gracefully, allowing in-flight requests/WebSocket connections
  // to complete within a timeout window.
  //
  // Timeline:
  // 1. Signal received → Stop accepting NEW connections
  // 2. Close server → Wait for in-flight requests (30s timeout)
  // 3. Exit → Process terminates, container restarts
  const signals = ['SIGTERM', 'SIGINT'];

  signals.forEach((signal) => {
    process.on(
      signal,
      () =>
        void (async () => {
          app.log.info(`Received ${signal}, initiating graceful shutdown...`);

          try {
            // Stop accepting new connections and close the server
            // Existing WebSocket connections and HTTP requests get time to complete
            await app.close();

            app.log.info('Server closed successfully, all connections drained');
            process.exit(0);
          } catch (err) {
            app.log.error(
              { error: err instanceof Error ? err.message : String(err) },
              'Error during graceful shutdown',
            );
            process.exit(1);
          }
        })(),
    );
  });

  // Handle uncaught exceptions → log and exit
  process.on('uncaughtException', (err) => {
    app.log.error(
      { error: err instanceof Error ? err.message : String(err) },
      'Uncaught exception, exiting',
    );
    process.exit(1);
  });

  // Handle unhandled promise rejections → log and exit
  process.on('unhandledRejection', (reason) => {
    app.log.error(
      { reason: reason instanceof Error ? reason.message : String(reason) },
      'Unhandled rejection, exiting',
    );
    process.exit(1);
  });
}

main().catch((err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});

import './loadEnv.js';
import * as Sentry from '@sentry/node';
import { hostname } from 'node:os';
import { SCHEMA_VERSION } from '@phalanxduel/shared';
import { metrics } from '@opentelemetry/api';
import { logs, SeverityNumber } from '@opentelemetry/api-logs';
import { BatchSpanProcessor, NodeTracerProvider } from '@opentelemetry/sdk-trace-node';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { OTLPLogExporter } from '@opentelemetry/exporter-logs-otlp-http';
import { MeterProvider, PeriodicExportingMetricReader } from '@opentelemetry/sdk-metrics';
import { BatchLogRecordProcessor, LoggerProvider } from '@opentelemetry/sdk-logs';
import { OTLPMetricExporter } from '@opentelemetry/exporter-metrics-otlp-http';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { ATTR_SERVICE_NAME } from '@opentelemetry/semantic-conventions';

interface MeterProviderWithAddMetricReader {
  addMetricReader(reader: PeriodicExportingMetricReader): void;
}

function hasAddMetricReader(value: unknown): value is MeterProviderWithAddMetricReader {
  return (
    typeof value === 'object' &&
    value !== null &&
    typeof Reflect.get(value, 'addMetricReader') === 'function'
  );
}

function normalizeOtlpEndpoint(endpoint: string): string {
  return endpoint
    .trim()
    .replace(/\/+$/u, '')
    .replace(/\/v1\/(traces|metrics|logs)$/u, '');
}

function envFlagEnabled(value: string | undefined): boolean {
  return value === '1' || value?.toLowerCase() === 'true';
}

const isProduction = process.env.NODE_ENV === 'production';
const sentryDsn = process.env.SENTRY_DSN;
// OTel collector endpoint with default to localhost:4318 (local development)
const otlpEndpointRaw = process.env.OTEL_EXPORTER_OTLP_ENDPOINT ?? 'http://localhost:4318';
const otlpEndpoint = normalizeOtlpEndpoint(otlpEndpointRaw);
const localSentryEnabled = envFlagEnabled(process.env.PHALANX_ENABLE_LOCAL_SENTRY);
const sentryEnabled = !!sentryDsn && (isProduction || localSentryEnabled);
const otlpConsoleLogsEnabled =
  process.env.OTEL_CONSOLE_LOGS_ENABLED === '1' ||
  process.env.OTEL_CONSOLE_LOGS_ENABLED?.toLowerCase() === 'true';
const serviceName = process.env.OTEL_SERVICE_NAME?.trim() ?? 'phalanxduel';
process.env.OTEL_SERVICE_NAME ??= serviceName;
const resource = resourceFromAttributes({
  [ATTR_SERVICE_NAME]: serviceName,
});

const integrations = [Sentry.consoleLoggingIntegration({ levels: ['log', 'warn', 'error'] })];

// Create OTLP trace exporter (primary telemetry path)
let traceExporter: OTLPTraceExporter | undefined;
try {
  traceExporter = new OTLPTraceExporter({
    url: `${otlpEndpoint}/v1/traces`,
  });
} catch (error) {
  console.warn(
    `[instrument.ts] Failed to initialize OTLP trace exporter at ${otlpEndpoint}:`,
    error instanceof Error ? error.message : error,
  );
}

if (!isProduction) {
  integrations.push(Sentry.spotlightIntegration());
}

// Try to load profiling integration if available
try {
  const { nodeProfilingIntegration } = await import('@sentry/profiling-node');
  if (nodeProfilingIntegration) {
    integrations.push(nodeProfilingIntegration());
  }
} catch {
  // Silently fail profiling if binary is missing or incompatible
}

// Initialize Sentry for error/exception capturing only (not span export).
// Spans are exported via OTLP to the local collector instead.
if (sentryEnabled) {
  Sentry.init({
    dsn: sentryDsn,
    release: process.env.SENTRY_RELEASE ?? `phalanxduel@${SCHEMA_VERSION}`,
    // The default Fastify integration from Sentry registers @fastify/otel, which
    // wraps route handlers assuming (request, reply) signature. This crashes on
    // WebSocket routes where the handler receives (socket, request) instead.
    // Use the function form so we actually replace defaults rather than merging.
    integrations: (defaults) => [...defaults.filter((i) => i.name !== 'Fastify'), ...integrations],
    // Structured log ingestion via Sentry.logger.* (errors and exceptions)
    enableLogs: true,
    // NOTE: Sentry span export is disabled. All spans go to OTLP collector.
    // Set tracesSampleRate=0 to prevent Sentry from sampling spans, since
    // we're using OTLP as the primary tracing backend.
    tracesSampleRate: 0,
    // Continuous profiling (SDK v8+ API)
    profileSessionSampleRate: process.env.SENTRY_PROFILES_SAMPLE_RATE
      ? parseFloat(process.env.SENTRY_PROFILES_SAMPLE_RATE)
      : 1.0,
    profileLifecycle: 'trace',
    environment: process.env.APP_ENV ?? process.env.NODE_ENV ?? 'development',
    debug: !isProduction && !!process.env.SENTRY_DEBUG,
    sendDefaultPii: true,

    initialScope: {
      tags: {
        'host.name': process.env.FLY_MACHINE_ID ?? hostname(),
        'cloud.provider': process.env.FLY_APP_NAME ? 'fly_io' : 'local',
        'cloud.region': process.env.FLY_REGION ?? 'unknown',
      },
    },
    // DO NOT dual-export spans to Sentry. OTLP is the primary tracing backend.
  });
} else {
  console.log('[instrument.ts] Sentry not enabled. Using OTLP for all telemetry.');
}

// ── OTLP Export Integration ─────────────────────────────────────────────────
// Primary telemetry backend: sends traces, metrics, and logs to local OTel collector.
// The collector (running on localhost:4318 by default) handles forwarding to
// configured backends (Sentry, Datadog, etc.) via its own configuration.
//
// Architecture:
//   app → OTLP exporter → localhost:4318 (OTel Collector) → backends
//
try {
  const metricExporter = new OTLPMetricExporter({
    url: `${otlpEndpoint}/v1/metrics`,
  });
  const metricReader = new PeriodicExportingMetricReader({
    exporter: metricExporter,
    exportIntervalMillis: 5000,
  });

  if (sentryEnabled && traceExporter) {
    // Sentry enabled for errors/exceptions. Attach OTLP metric exporter to Sentry's meter provider.
    const meterProvider = metrics.getMeterProvider() as unknown;
    if (hasAddMetricReader(meterProvider)) {
      meterProvider.addMetricReader(metricReader);
    } else {
      const fallbackMeterProvider = new MeterProvider({
        resource,
        readers: [metricReader],
      });
      metrics.setGlobalMeterProvider(fallbackMeterProvider);
    }
  } else if (traceExporter) {
    // OTLP-only mode (no Sentry): register standalone OpenTelemetry SDK providers.
    const tracerProvider = new NodeTracerProvider({
      resource,
      spanProcessors: [new BatchSpanProcessor(traceExporter)],
    });
    tracerProvider.register();

    const meterProvider = new MeterProvider({
      resource,
      readers: [metricReader],
    });
    metrics.setGlobalMeterProvider(meterProvider);
  } else {
    console.error(
      '[instrument.ts] OTLP endpoint configured but trace exporter initialization failed. ' +
        'Telemetry will not be exported.',
    );
  }
} catch (error) {
  console.error(
    '[instrument.ts] Failed to initialize OTLP metric exporter:',
    error instanceof Error ? error.message : error,
  );
}

// ── OTLP Console Log Forwarding (Opt-in) ────────────────────────────────────
// Disabled by default to avoid behavior changes. Enable with:
//   OTEL_CONSOLE_LOGS_ENABLED=1
if (otlpEndpoint && otlpConsoleLogsEnabled) {
  const CONSOLE_PATCH_FLAG = Symbol.for('phalanx.otel.console.patched');
  const globalObj = globalThis as Record<symbol, boolean>;

  if (!globalObj[CONSOLE_PATCH_FLAG]) {
    globalObj[CONSOLE_PATCH_FLAG] = true;

    const logExporter = new OTLPLogExporter({
      url: `${otlpEndpoint}/v1/logs`,
    });

    const loggerProvider = new LoggerProvider({
      resource,
      processors: [new BatchLogRecordProcessor(logExporter)],
    });
    logs.setGlobalLoggerProvider(loggerProvider);

    const logger = loggerProvider.getLogger('node.console', '1.0.0');

    const toMessage = (args: unknown[]): string =>
      args
        .map((arg) => {
          if (typeof arg === 'string') return arg;
          if (arg instanceof Error) return arg.stack ?? arg.message;
          try {
            return JSON.stringify(arg);
          } catch {
            return String(arg);
          }
        })
        .join(' ');

    const emit = (severityNumber: SeverityNumber, severityText: string, args: unknown[]) => {
      try {
        logger.emit({
          severityNumber,
          severityText,
          body: toMessage(args),
          attributes: {},
        });
      } catch {
        // Never break runtime behavior if log export fails.
      }
    };

    const originalConsole = {
      log: console.log,
      info: console.info,
      warn: console.warn,
      error: console.error,
    };

    console.log = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.log.apply(console, args);
    };

    console.info = (...args: unknown[]) => {
      emit(SeverityNumber.INFO, 'INFO', args);
      originalConsole.info.apply(console, args);
    };

    console.warn = (...args: unknown[]) => {
      emit(SeverityNumber.WARN, 'WARN', args);
      originalConsole.warn.apply(console, args);
    };

    console.error = (...args: unknown[]) => {
      emit(SeverityNumber.ERROR, 'ERROR', args);
      originalConsole.error.apply(console, args);
    };

    const flushLogs = async () => {
      try {
        await loggerProvider.forceFlush();
      } catch {
        // Ignore flush errors on shutdown.
      }
    };
    process.once('beforeExit', () => {
      void flushLogs();
    });
  }
}

import { existsSync, readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parseEnv } from 'node:util';

const RUNTIME_UNSAFE_ENV_KEYS = new Set(['NODE_OPTIONS']);
const EXTERNALLY_DEFINED_ENV_KEYS = new Set(Object.keys(process.env));

function loadEnvFile(path: string, overrideExisting: boolean): void {
  if (!existsSync(path)) return;

  const raw = readFileSync(path, 'utf8');
  const parsed = parseEnv(raw);

  for (const [key, value] of Object.entries(parsed)) {
    // NODE_OPTIONS can crash worker-based subsystems (e.g. pino transports)
    // when injected after process boot. Respect only externally provided values.
    if (RUNTIME_UNSAFE_ENV_KEYS.has(key)) continue;

    // Let shell/runner-provided env win over file values.
    if (overrideExisting && EXTERNALLY_DEFINED_ENV_KEYS.has(key)) continue;

    if (overrideExisting ?? process.env[key] === undefined) {
      process.env[key] = value;
    }
  }
}

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, '../..');

// 1. Determine environment (APP_ENV > NODE_ENV > local)
const appEnv =
  process.env.APP_ENV ?? (process.env.NODE_ENV === 'production' ? 'production' : 'local');

// 2. Load hierarchy
// Base .env (Always loaded first as defaults)
loadEnvFile(resolve(repoRoot, '.env'), false);

// Environment-specific .env (e.g. .env.staging, .env.production, .env.test)
// These OVERRIDE base .env defaults
if (appEnv !== 'local') {
  loadEnvFile(resolve(repoRoot, `.env.${appEnv}`), true);
}

// Local developer overrides (Global for all local envs)
loadEnvFile(resolve(repoRoot, '.env.local'), true);

// Environment-specific local overrides (e.g. .env.staging.local)
loadEnvFile(resolve(repoRoot, `.env.${appEnv}.local`), true);

import { randomUUID } from 'node:crypto';
import type { WebSocket } from 'ws';
import type {
  GameState,
  Action,
  ServerMessage,
  GameOptions,
  PlayerState,
  CreateMatchParamsPartial,
  PhalanxTurnResult,
  PhalanxEvent,
  MatchEventLog,
  Battlefield,
  TransactionLogEntry,
} from '@phalanxduel/shared';
import { DEFAULT_MATCH_PARAMS, TelemetryName } from '@phalanxduel/shared';
import { computeStateHash, computeTurnHash } from '@phalanxduel/shared/hash';
import {
  createInitialState,
  applyAction,
  computeBotAction,
  deriveEventsFromEntry,
  type BotConfig,
} from '@phalanxduel/engine';
import type { GameConfig } from '@phalanxduel/engine';
import { GameTelemetry } from './telemetry.js';
import * as Sentry from '@sentry/node';
import { MatchRepository } from './db/match-repo.js';
import { LadderService } from './ladder.js';
import { matchLifecycleTotal } from './metrics.js';

export class MatchError extends Error {
  constructor(
    message: string,
    public readonly code: string,
  ) {
    super(message);
    this.name = 'MatchError';
  }
}

export class ActionError extends Error {
  constructor(
    public readonly matchId: string,
    message: string,
    public readonly code: string,
  ) {
    super(message);
    this.name = 'ActionError';
  }
}

interface PlayerConnection {
  playerId: string;
  playerName: string;
  playerIndex: number;
  userId?: string;
  socket: WebSocket | null;
}

interface SpectatorConnection {
  spectatorId: string;
  socket: WebSocket | null;
}

type SocketInfo =
  | { matchId: string; playerId: string; isSpectator: false }
  | { matchId: string; spectatorId: string; isSpectator: true };

export interface BotMatchOptions {
  opponent: 'bot-random' | 'bot-heuristic';
  botConfig: BotConfig;
}

interface CreateMatchOptions {
  gameOptions?: GameOptions;
  rngSeed?: number;
  botOptions?: BotMatchOptions;
  matchParams?: CreateMatchParamsPartial;
  userId?: string;
  creatorIp?: string;
}

export interface MatchInstance {
  matchId: string;
  creatorIp?: string;
  players: [PlayerConnection | null, PlayerConnection | null];
  spectators: SpectatorConnection[];
  state: GameState | null;
  config: GameConfig | null;
  actionHistory: Action[];
  gameOptions?: GameOptions;
  rngSeed?: number;
  matchParams?: CreateMatchParamsPartial;
  botConfig?: BotConfig;
  botPlayerIndex?: 0 | 1;
  botStrategy?: 'random' | 'heuristic';
  lastEvents?: PhalanxEvent[];
  lastPreState: GameState | null;
  lifecycleEvents: PhalanxEvent[];
  createdAt: number;
  lastActivityAt: number;
}

const MAX_ACTIVE_MATCHES_PER_IP = 3;
const MAX_SPECTATORS_PER_MATCH = 50;
const RECONNECT_WINDOW_MS = 2 * 60 * 1000; // 2 minutes

function resolveMatchParams(
  matchParams?: CreateMatchParamsPartial,
): NonNullable<GameConfig['matchParams']> {
  const rows = matchParams?.rows ?? DEFAULT_MATCH_PARAMS.rows;
  const columns = matchParams?.columns ?? DEFAULT_MATCH_PARAMS.columns;

  // RULES.md § 3.3: Total slots cannot exceed 48
  if (rows * columns > 48) {
    throw new MatchError(
      `Invalid config: total slots (${rows * columns}) cannot exceed 48`,
      'INVALID_MATCH_PARAMS',
    );
  }

  // RULES.md § 3.3: maxHandSize cannot exceed columns
  const defaultMaxHandSize = Math.min(DEFAULT_MATCH_PARAMS.maxHandSize, columns);
  if (matchParams?.maxHandSize !== undefined && matchParams.maxHandSize > columns) {
    throw new MatchError(
      `Invalid config: maxHandSize (${matchParams.maxHandSize}) cannot exceed columns (${columns})`,
      'INVALID_MATCH_PARAMS',
    );
  }
  const maxHandSize = matchParams?.maxHandSize ?? defaultMaxHandSize;

  // RULES.md § 3.3: initialDraw = rows * columns + columns
  const expectedInitialDraw = rows * columns + columns;
  if (matchParams?.initialDraw !== undefined && matchParams.initialDraw !== expectedInitialDraw) {
    throw new MatchError(
      `Invalid config: initialDraw must equal rows * columns + columns (${expectedInitialDraw})`,
      'INVALID_MATCH_PARAMS',
    );
  }
  const initialDraw = expectedInitialDraw;

  return { rows, columns, maxHandSize, initialDraw };
}

function send(socket: WebSocket | null, message: ServerMessage): void {
  if (socket?.readyState === 1) {
    socket.send(JSON.stringify(message));
  }
}

function redactBattlefield(battlefield: Battlefield): Battlefield {
  return battlefield.map((cell) => {
    if (!cell?.faceDown) return cell;
    // Redact card details when face-down
    return {
      ...cell,
      card: {
        id: cell.card.id, // ID is needed for sync/referencing
        suit: 'spades', // Placeholder
        face: '?', // Hidden
        value: 0, // Hidden
        type: 'number', // Placeholder
      },
    };
  });
}

function redactHiddenCards(playerState: PlayerState): PlayerState {
  const { hand, drawpile, battlefield, discardPile, ...rest } = playerState;
  return {
    ...rest,
    battlefield: redactBattlefield(battlefield),
    hand: [],
    drawpile: [],
    // Show only the top card of the discard pile if it exists
    discardPile: discardPile.slice(-1),
    handCount: hand.length,
    drawpileCount: drawpile.length,
    discardPileCount: discardPile.length,
  };
}

function redactPhalanxEvents(events: PhalanxEvent[]): PhalanxEvent[] {
  return events;
}

/** Redact card details in event log for public/spectator view */
export function filterEventLogForPublic(log: MatchEventLog): MatchEventLog {
  const events = redactPhalanxEvents(log.events);
  const fingerprint = computeStateHash(events);
  return {
    ...log,
    events,
    fingerprint,
  };
}

/**
 * Builds the unified MatchEventLog for a match: lifecycle events prepended to
 * all turn-derived events in sequence order, with a SHA-256 fingerprint.
 */
export function buildMatchEventLog(match: MatchInstance): MatchEventLog {
  const turnEvents: PhalanxEvent[] = (match.state?.transactionLog ?? []).flatMap((entry) =>
    deriveEventsFromEntry(entry, match.matchId),
  );
  const events = [...match.lifecycleEvents, ...turnEvents];
  const fingerprint = computeStateHash(events);
  return {
    matchId: match.matchId,
    events,
    fingerprint,
    generatedAt: new Date().toISOString(),
  };
}

function redactTransactionLog(
  log: TransactionLogEntry[] | undefined,
): TransactionLogEntry[] | undefined {
  return log;
}

/** Redact both players' hands/drawpiles for spectator view */
export function filterStateForSpectator(state: GameState): GameState {
  const [p0, p1] = state.players;
  if (!p0 || !p1) throw new Error('GameState must have exactly 2 players');
  return {
    ...state,
    players: [redactHiddenCards(p0), redactHiddenCards(p1)],
    transactionLog: redactTransactionLog(state.transactionLog),
  };
}

/** Redact opponent hand/drawpile/discard, replace with counts */
export function filterStateForPlayer(state: GameState, playerIndex: number): GameState {
  const redactOrKeep = (ps: PlayerState, idx: number): PlayerState => {
    if (idx === playerIndex) {
      // Current player sees their own full discard pile
      return {
        ...ps,
        discardPileCount: ps.discardPile.length,
      };
    }
    return redactHiddenCards(ps);
  };
  const [p0, p1] = state.players;
  if (!p0 || !p1) throw new Error('GameState must have exactly 2 players');
  return {
    ...state,
    players: [redactOrKeep(p0, 0), redactOrKeep(p1, 1)],
    transactionLog: redactTransactionLog(state.transactionLog),
  };
}

/** TTL constants in milliseconds */
const GAME_OVER_TTL = 5 * 60 * 1000; // 5 minutes
const ABANDONED_TTL = 10 * 60 * 1000; // 10 minutes

export class MatchManager {
  matches = new Map<string, MatchInstance>();
  socketMap = new Map<WebSocket, SocketInfo>();
  /** Tracks pending reconnect timeouts keyed by `matchId:playerId` */
  disconnectTimers = new Map<string, ReturnType<typeof setTimeout>>();
  onMatchRemoved: (() => void) | null = null;
  private matchRepo = new MatchRepository();
  private ladderService = new LadderService();

  async getMatch(matchId: string): Promise<MatchInstance | null> {
    const match = this.matches.get(matchId);
    if (match) return match;

    const dbMatch = await this.matchRepo.getMatch(matchId);
    if (dbMatch) {
      this.matches.set(matchId, dbMatch);
      return dbMatch;
    }

    return null;
  }

  getMatchSync(matchId: string): MatchInstance | undefined {
    return this.matches.get(matchId);
  }

  broadcastMatchState(matchId: string): void {
    void (async () => {
      const match = await this.getMatch(matchId);
      if (match) {
        this.broadcastState(match);
      }
    })();
  }

  createMatch(
    playerName: string,
    socket: WebSocket | null,
    options?: CreateMatchOptions,
  ): { matchId: string; playerId: string; playerIndex: number } {
    const { gameOptions, rngSeed, botOptions, matchParams, userId, creatorIp } = options ?? {};

    // Enforce IP-based limit for active matches
    if (creatorIp) {
      const activeFromIp = Array.from(this.matches.values()).filter(
        (m) => m.creatorIp === creatorIp && m.state?.phase !== 'gameOver',
      ).length;

      if (activeFromIp >= MAX_ACTIVE_MATCHES_PER_IP) {
        throw new MatchError(
          `Too many active matches from this IP (max ${MAX_ACTIVE_MATCHES_PER_IP})`,
          'MATCH_LIMIT_REACHED',
        );
      }
    }

    const matchId = randomUUID();
    const playerId = randomUUID();
    const playerIndex = 0;

    const player: PlayerConnection = {
      playerId,
      playerName,
      playerIndex,
      userId,
      socket,
    };

    const now = Date.now();
    const createdAt = new Date(now).toISOString();
    const match: MatchInstance = {
      matchId,
      creatorIp,
      players: [player, null],
      spectators: [],
      state: null,
      config: null,
      actionHistory: [],
      gameOptions,
      rngSeed,
      matchParams,
      lastPreState: null,
      lifecycleEvents: [],
      createdAt: now,
      lastActivityAt: now,
    };

    // match.created: record match parameters (rngSeed omitted for fairness)
    match.lifecycleEvents.push({
      id: `${matchId}:lc:match_created`,
      type: 'functional_update',
      name: TelemetryName.EVENT_MATCH_CREATED,
      timestamp: createdAt,
      payload: {
        matchId,
        params: {
          rows: matchParams?.rows ?? DEFAULT_MATCH_PARAMS.rows,
          columns: matchParams?.columns ?? DEFAULT_MATCH_PARAMS.columns,
          maxHandSize: matchParams?.maxHandSize ?? DEFAULT_MATCH_PARAMS.maxHandSize,
          initialDraw: matchParams?.initialDraw ?? DEFAULT_MATCH_PARAMS.initialDraw,
          gameOptions: gameOptions ?? null,
        },
        createdAt,
      },
      status: 'ok',
    });

    // player.joined for the match creator (P0)
    match.lifecycleEvents.push({
      id: `${matchId}:lc:player_0_joined`,
      type: 'functional_update',
      name: TelemetryName.EVENT_PLAYER_JOINED,
      timestamp: createdAt,
      payload: { playerId, playerIndex: 0, isBot: false, joinedAt: createdAt },
      status: 'ok',
    });

    if (botOptions) {
      const botPlayerId = randomUUID();
      const botPlayer: PlayerConnection = {
        playerId: botPlayerId,
        playerName: botOptions.opponent === 'bot-heuristic' ? 'Bot (Heuristic)' : 'Bot (Random)',
        playerIndex: 1,
        socket: null,
      };
      match.players[1] = botPlayer;
      match.botConfig = botOptions.botConfig;
      match.botPlayerIndex = 1;
      match.botStrategy = botOptions.opponent === 'bot-heuristic' ? 'heuristic' : 'random';

      // player.joined for the bot (P1)
      match.lifecycleEvents.push({
        id: `${matchId}:lc:player_1_joined`,
        type: 'functional_update',
        name: TelemetryName.EVENT_PLAYER_JOINED,
        timestamp: createdAt,
        payload: { playerId: botPlayerId, playerIndex: 1, isBot: true, joinedAt: createdAt },
        status: 'ok',
      });
    }

    this.matches.set(matchId, match);
    if (socket) {
      this.socketMap.set(socket, { matchId, playerId, isSpectator: false });
    }

    matchLifecycleTotal.add('created');

    // For bot matches, initialize the game immediately
    if (botOptions) {
      this.initializeGame(match);
    }

    void this.matchRepo.saveMatch(match);

    return { matchId, playerId, playerIndex };
  }

  createPendingMatch(matchId = randomUUID()): { matchId: string } {
    const now = Date.now();
    const createdAt = new Date(now).toISOString();
    const match: MatchInstance = {
      matchId,
      players: [null, null],
      spectators: [],
      state: null,
      config: null,
      actionHistory: [],
      lastPreState: null,
      lifecycleEvents: [],
      createdAt: now,
      lastActivityAt: now,
    };

    match.lifecycleEvents.push({
      id: `${matchId}:lc:match_created`,
      type: 'functional_update',
      name: TelemetryName.EVENT_MATCH_CREATED,
      timestamp: createdAt,
      payload: {
        matchId,
        params: {
          rows: DEFAULT_MATCH_PARAMS.rows,
          columns: DEFAULT_MATCH_PARAMS.columns,
          maxHandSize: DEFAULT_MATCH_PARAMS.maxHandSize,
          initialDraw: DEFAULT_MATCH_PARAMS.initialDraw,
          gameOptions: null,
        },
        createdAt,
      },
      status: 'ok',
    });

    this.matches.set(matchId, match);
    return { matchId };
  }

  async joinMatch(
    matchId: string,
    playerName: string,
    socket: WebSocket,
    userId?: string,
  ): Promise<{ playerId: string; playerIndex: number }> {
    const match = await this.getMatch(matchId);
    if (!match) {
      throw new MatchError('Match not found', 'MATCH_NOT_FOUND');
    }
    if (match.players[0] !== null && match.players[1] !== null) {
      throw new MatchError('Match is full', 'MATCH_FULL');
    }

    const playerId = randomUUID();
    const playerIndex = match.players[0] === null ? 0 : 1;

    const player: PlayerConnection = {
      playerId,
      playerName,
      playerIndex,
      userId,
      socket,
    };

    match.players[playerIndex] = player;
    match.lastActivityAt = Date.now();
    this.socketMap.set(socket, { matchId, playerId, isSpectator: false });

    const joinedAt = new Date().toISOString();
    match.lifecycleEvents.push({
      id: `${matchId}:lc:player_${playerIndex}_joined`,
      type: 'functional_update',
      name: TelemetryName.EVENT_PLAYER_JOINED,
      timestamp: joinedAt,
      payload: { playerId, playerIndex, isBot: false, joinedAt },
      status: 'ok',
    });

    // REST-created pending matches may have no host yet; only initialize once both slots are filled.
    if (match.players[0] === null || match.players[1] === null) {
      return { playerId, playerIndex };
    }

    this.initializeGame(match);
    void this.matchRepo.saveMatch(match);

    // Note: caller is responsible for sending matchJoined before calling broadcastState
    return { playerId, playerIndex };
  }

  async rejoinMatch(
    matchId: string,
    playerId: string,
    socket: WebSocket,
  ): Promise<{ playerIndex: number }> {
    const match = await this.getMatch(matchId);
    if (!match) {
      throw new MatchError('Match not found', 'MATCH_NOT_FOUND');
    }

    const player = match.players.find((p) => p?.playerId === playerId);
    if (!player) {
      throw new MatchError('Player not found in this match', 'PLAYER_NOT_FOUND');
    }

    if (player.socket?.readyState === 1) {
      throw new MatchError('Player is already connected', 'ALREADY_CONNECTED');
    }

    // Cancel the forfeit timer
    const timerKey = `${matchId}:${playerId}`;
    const timer = this.disconnectTimers.get(timerKey);
    if (timer) {
      clearTimeout(timer);
      this.disconnectTimers.delete(timerKey);
    }

    // Swap in the new socket
    player.socket = socket;
    match.lastActivityAt = Date.now();
    this.socketMap.set(socket, { matchId, playerId, isSpectator: false });

    // Notify opponent
    const opponent = match.players.find((p) => p !== null && p.playerId !== playerId);
    if (opponent) {
      send(opponent.socket, { type: 'opponentReconnected', matchId });
    }

    return { playerIndex: player.playerIndex };
  }

  async watchMatch(matchId: string, socket: WebSocket): Promise<{ spectatorId: string }> {
    const match = await this.getMatch(matchId);
    if (!match) {
      throw new MatchError('Match not found', 'MATCH_NOT_FOUND');
    }

    if (match.spectators.length >= MAX_SPECTATORS_PER_MATCH) {
      throw new MatchError(
        `Too many spectators for this match (max ${MAX_SPECTATORS_PER_MATCH})`,
        'SPECTATOR_LIMIT_REACHED',
      );
    }

    const spectatorId = randomUUID();
    const spectator: SpectatorConnection = { spectatorId, socket };

    match.spectators.push(spectator);
    match.lastActivityAt = Date.now();
    this.socketMap.set(socket, { matchId, spectatorId, isSpectator: true });

    return { spectatorId };
  }

  updatePlayerIdentity(socket: WebSocket, userId: string, playerName: string): void {
    const info = this.socketMap.get(socket);
    if (!info || info.isSpectator) return;
    const match = this.matches.get(info.matchId);
    if (!match) return;
    const player = match.players.find((p) => p?.playerId === info.playerId);
    if (!player) return;
    player.userId = userId;
    player.playerName = playerName;
  }

  handleDisconnect(socket: WebSocket): void {
    void (async () => {
      const info = this.socketMap.get(socket);
      if (!info) return;

      this.socketMap.delete(socket);
      const match = await this.getMatch(info.matchId);
      if (!match) return;

      if (info.isSpectator) {
        const idx = match.spectators.findIndex((s) => s.spectatorId === info.spectatorId);
        if (idx !== -1) match.spectators.splice(idx, 1);
        // Re-broadcast so players see updated spectator count
        this.broadcastState(match);
        return;
      }

      const player = match.players.find((p) => p?.playerId === info.playerId);
      if (player) {
        player.socket = null;
      }

      // Notify opponent
      const opponent = match.players.find((p) => p !== null && p.playerId !== info.playerId);
      if (opponent) {
        send(opponent.socket, {
          type: 'opponentDisconnected',
          matchId: info.matchId,
        });
      }

      // Start reconnect timer — forfeit after RECONNECT_WINDOW_MS if game is active
      if (match.state && match.state.phase !== 'gameOver') {
        const timerKey = `${info.matchId}:${info.playerId}`;
        // Don't double-start if there's already a timer (shouldn't happen, but be safe)
        if (!this.disconnectTimers.has(timerKey)) {
          const timer = setTimeout(() => {
            this.disconnectTimers.delete(timerKey);
            void this.forfeitDisconnectedPlayer(info.matchId, info.playerId);
          }, RECONNECT_WINDOW_MS);
          this.disconnectTimers.set(timerKey, timer);
        }
      }
    })();
  }

  /** Forfeit a disconnected player after the reconnect window expires. */
  private async forfeitDisconnectedPlayer(matchId: string, playerId: string): Promise<void> {
    const match = await this.getMatch(matchId);
    if (!match?.state || match.state.phase === 'gameOver') return;

    const player = match.players.find((p) => p?.playerId === playerId);
    // If they reconnected in the meantime, their socket won't be null
    if (!player || player.socket?.readyState === 1) return;

    try {
      await this.handleAction(matchId, playerId, {
        type: 'forfeit',
        playerIndex: player.playerIndex,
        timestamp: new Date().toISOString(),
      });
    } catch {
      // Match may have ended naturally — ignore
    }
  }

  /** Remove stale matches: gameOver after 5 min, abandoned after 10 min */
  cleanupMatches(): number {
    const now = Date.now();
    let removed = 0;
    for (const [matchId, match] of this.matches) {
      const isGameOver = match.state?.phase === 'gameOver';
      const elapsed = now - match.lastActivityAt;
      if ((isGameOver && elapsed > GAME_OVER_TTL) || elapsed > ABANDONED_TTL) {
        if (!isGameOver) {
          matchLifecycleTotal.add('abandoned');
        }
        // Clean up player socket references
        for (const player of match.players) {
          if (player?.socket) {
            this.socketMap.delete(player.socket);
          }
        }
        // Clean up spectator socket references
        for (const spectator of match.spectators) {
          if (spectator.socket) {
            this.socketMap.delete(spectator.socket);
          }
        }
        this.matches.delete(matchId);
        this.onMatchRemoved?.();
        removed++;
      }
    }
    return removed;
  }

  private initializeGame(match: MatchInstance): void {
    const p0 = match.players[0];
    const p1 = match.players[1];
    if (!p0 || !p1) {
      throw new MatchError('Match is not ready to start', 'MATCH_NOT_READY');
    }
    const rngSeed = match.rngSeed ?? Date.now();
    const resolvedMatchParams = resolveMatchParams(match.matchParams);
    const config: GameConfig = {
      matchId: match.matchId,
      players: [
        { id: p0.playerId, name: p0.playerName },
        { id: p1.playerId, name: p1.playerName },
      ],
      rngSeed,
      drawTimestamp: new Date().toISOString(),
      gameOptions: match.gameOptions,
      matchParams: resolvedMatchParams,
    };
    // createInitialState handles initial 12-card draw and sets phase to StartTurn
    const preInitState = createInitialState(config);
    match.lastPreState = preInitState;

    // Transition to the first action phase via system:init (mode-dependent).
    const initTimestamp = new Date().toISOString();
    match.state = applyAction(
      preInitState,
      {
        type: 'system:init',
        timestamp: initTimestamp,
      },
      {
        hashFn: (s) => computeStateHash(s),
      },
    );
    match.config = config;

    // game.initialized: capture the initial state hash from the system:init entry
    const initEntry = match.state.transactionLog?.at(-1);
    const initialStateHash = initEntry?.stateHashAfter ?? computeStateHash(match.state);
    match.lifecycleEvents.push({
      id: `${match.matchId}:lc:game_initialized`,
      type: 'functional_update',
      name: TelemetryName.EVENT_GAME_INITIALIZED,
      timestamp: initTimestamp,
      payload: { initialStateHash },
      status: 'ok',
    });

    matchLifecycleTotal.add('started');
    if (match.state.phase !== preInitState.phase) {
      GameTelemetry.recordPhaseTransition(match.matchId, preInitState.phase, match.state.phase);
    }

    this.scheduleBotTurn(match);
  }

  async handleAction(matchId: string, playerId: string, action: Action): Promise<void> {
    const match = await this.getMatch(matchId);
    if (!match) {
      throw new ActionError(matchId, 'Match not found', 'MATCH_NOT_FOUND');
    }

    const player = match.players.find((p) => p?.playerId === playerId);
    if (!player) {
      throw new ActionError(matchId, 'Player not found in this match', 'PLAYER_NOT_FOUND');
    }

    // Prevent player index spoofing: verify the action's playerIndex matches
    // the actual index of the authenticated player's WebSocket connection.
    if ('playerIndex' in action) {
      const actualIndex = match.players.indexOf(player);
      if (action.playerIndex !== actualIndex) {
        throw new ActionError(
          matchId,
          'Player index does not match authenticated identity',
          'UNAUTHORIZED_ACTION',
        );
      }
    }

    if (!match.state) {
      throw new ActionError(matchId, 'Game not initialized', 'GAME_NOT_INIT');
    }

    // Apply the action with hash and timestamp for transaction log
    match.lastActivityAt = Date.now();

    await GameTelemetry.recordAction(matchId, action, async (): Promise<PhalanxTurnResult> => {
      if (!match.state) throw new ActionError(matchId, 'Game not initialized', 'GAME_NOT_INIT');
      const preState = match.state;
      match.lastPreState = preState;
      // Normalize to server timestamp before applying so the stored action and the
      // applyAction call use the same timestamp — replay reads action.timestamp and
      // must match the timestamp used for card ID generation during the live game.
      const serverAction = { ...action, timestamp: new Date().toISOString() };
      const postState = applyAction(preState, serverAction, {
        hashFn: (s) => computeStateHash(s),
      });

      match.state = postState;
      match.actionHistory.push(serverAction);

      // Derive events from the latest transaction log entry
      const lastEntry = postState.transactionLog?.at(-1);
      match.lastEvents = lastEntry ? deriveEventsFromEntry(lastEntry, matchId) : [];

      // Persist the canonical turn digest on the log entry (RULES.md §20.2)
      if (lastEntry && match.lastEvents.length > 0) {
        lastEntry.turnHash = computeTurnHash(
          lastEntry.stateHashAfter,
          match.lastEvents.map((e) => e.id),
        );
      }

      if (lastEntry) {
        // Per-action audit persistence (TASK-24)
        void this.matchRepo.saveTransactionLogEntry(
          matchId,
          lastEntry.sequenceNumber,
          lastEntry,
          match.lastEvents,
        );

        if (lastEntry.action.type === 'system:init') {
          Sentry.addBreadcrumb({
            category: 'game.system',
            message: 'Game Initialized',
            data: { matchId },
          });
        }
        if (lastEntry.details.type === 'attack' && lastEntry.details.combat) {
          const combat = lastEntry.details.combat;
          Sentry.addBreadcrumb({
            category: 'game.combat',
            message: `Attack: ${combat.attackerCard.face}${combat.attackerCard.suit[0]} deals ${combat.totalLpDamage} LP damage`,
            data: { matchId, turn: combat.turnNumber },
          });
        }
      }

      return {
        matchId,
        playerId,
        preState,
        postState,
        action,
      };
    });

    // Broadcast updated state
    this.broadcastState(match);

    // Schedule bot turn if this is a bot match
    this.scheduleBotTurn(match);

    // Await save so the completed match is in the DB before computing Elo
    await this.matchRepo.saveMatch(match);

    // Persist the event log (fire-and-forget — does not block action response)
    void this.matchRepo.saveEventLog(matchId, buildMatchEventLog(match));

    if (match.state?.phase === 'gameOver') {
      this.maybeEmitGameCompleted(match, matchId);

      // TASK-106: Persist final state hash for durable audit trail
      const finalHash = computeStateHash(match.state);
      void this.matchRepo.saveFinalStateHash(matchId, finalHash);

      void this.ladderService.onMatchComplete({
        player1Id: match.players[0]?.userId ?? null,
        player2Id: match.players[1]?.userId ?? null,
        botStrategy: match.botStrategy ?? null,
      });
    }
  }

  /** Emits game.completed once when the match first reaches gameOver. */
  private maybeEmitGameCompleted(match: MatchInstance, matchId: string): void {
    const alreadyCompleted = match.lifecycleEvents.some(
      (e) => e.name === TelemetryName.EVENT_GAME_COMPLETED,
    );
    if (alreadyCompleted) return;

    const completedAt = new Date().toISOString();
    const state = match.state;
    if (!state) return;
    const outcome = state.outcome;
    match.lifecycleEvents.push({
      id: `${matchId}:lc:game_completed`,
      type: 'functional_update',
      name: TelemetryName.EVENT_GAME_COMPLETED,
      timestamp: completedAt,
      payload: {
        winnerIndex: outcome?.winnerIndex ?? null,
        victoryType: outcome?.victoryType ?? null,
        turnNumber: outcome?.turnNumber ?? state.turnNumber,
        finalLp: [state.players[0]?.lifepoints ?? 0, state.players[1]?.lifepoints ?? 0],
        durationMs: Date.now() - match.createdAt,
      },
      status: 'ok',
    });
  }

  private scheduleBotTurn(match: MatchInstance): void {
    if (!match.botConfig || !match.state) return;
    if (match.state.phase === 'gameOver') return;

    if (match.botPlayerIndex == null) return;
    const botIdx = match.botPlayerIndex;
    if (match.state.activePlayerIndex !== botIdx) return;

    const botPlayer = match.players[botIdx];
    if (!botPlayer) return;

    setTimeout(() => {
      if (!match.state || match.state.phase === 'gameOver') return;
      if (match.state.activePlayerIndex !== botIdx) return;
      if (!match.botConfig) return;

      const turnSeed = match.botConfig.seed + match.state.turnNumber;
      const action = computeBotAction(match.state, botIdx, {
        ...match.botConfig,
        seed: turnSeed,
      });

      void this.handleAction(match.matchId, botPlayer.playerId, action).catch(() => {
        // Bot generated invalid action — handleAction already logs via telemetry
      });
      // handleAction calls broadcastState and scheduleBotTurn, so no recursion needed
    }, 300);
  }

  private broadcastState(match: MatchInstance): void {
    if (!match.state) return;
    const spectatorCount = match.spectators.length;
    const lastAction = match.actionHistory[match.actionHistory.length - 1] ?? {
      type: 'system:init',
      timestamp: new Date().toISOString(),
    };
    const lastEntry = match.state?.transactionLog?.at(-1);
    const turnHash =
      lastEntry && match.lastEvents?.length
        ? computeTurnHash(
            lastEntry.stateHashAfter,
            match.lastEvents.map((e) => e.id),
          )
        : undefined;

    const preStateSource = match.lastPreState ?? match.state;

    for (const player of match.players) {
      if (player && player.socket) {
        const playerState = filterStateForPlayer(match.state, player.playerIndex);
        const playerPreState = filterStateForPlayer(preStateSource, player.playerIndex);
        send(player.socket, {
          type: 'gameState',
          matchId: match.matchId,
          result: {
            matchId: match.matchId,
            playerId: player.playerId,
            preState: playerPreState,
            postState: playerState,
            action: lastAction,
            events: match.lastEvents ?? [],
            turnHash,
          },
          spectatorCount,
        });
      }
    }
    const spectatorState = filterStateForSpectator(match.state);
    const spectatorPreState = filterStateForSpectator(preStateSource);
    for (const spectator of match.spectators) {
      if (spectator.socket) {
        send(spectator.socket, {
          type: 'gameState',
          matchId: match.matchId,
          result: {
            matchId: match.matchId,
            playerId: 'spectator',
            preState: spectatorPreState,
            postState: spectatorState,
            action: lastAction,
            events: match.lastEvents ?? [],
            turnHash,
          },
          spectatorCount,
        });
      }
    }
  }
}

import type { FastifyInstance, FastifyRequest } from 'fastify';
import type { PhalanxEvent, MatchEventLog } from '@phalanxduel/shared';
import { MatchRepository } from '../db/match-repo.js';
import { MatchManager, buildMatchEventLog, filterEventLogForPublic } from '../match.js';
import { httpTraceContext, traceHttpHandler } from '../tracing.js';

type CompactEvent = Record<string, unknown>;

function getRequesterIdentity(request: FastifyRequest): { userId?: string; isAdmin: boolean } {
  // checkBasicAuth logic is in app.ts, but we can't easily call it here
  // for now, we'll assume not admin unless we add a proper decorator.
  // TODO: Add admin decorator to Fastify

  let userId: string | undefined;
  try {
    const token =
      request.headers.authorization?.replace('Bearer ', '') ?? request.cookies.phalanx_refresh;
    if (token) {
      const payload = (
        request.server as unknown as { jwt: { verify: (t: string) => { id: string } } }
      ).jwt.verify(token);
      userId = payload.id;
    }
  } catch {
    // Ignore invalid tokens
  }

  return { userId, isAdmin: false };
}

async function authorizeLogAccess(
  matchId: string,
  log: MatchEventLog,
  request: FastifyRequest,
  matchManager: MatchManager,
): Promise<MatchEventLog> {
  const { userId } = getRequesterIdentity(request);

  // 1. Check if requester is a participant (via userId)
  const match = await matchManager.getMatch(matchId);
  const isParticipant =
    (match?.players.some((p) => p?.userId === userId) ?? false) ||
    // Also check if the playerId is provided in a header (for anonymous participants)
    // Note: This is weak auth, but better than nothing for non-registered users.
    (match?.players.some((p) => p?.playerId === request.headers['x-phalanx-player-id']) ?? false);

  const isCompleted =
    match?.state?.phase === 'gameOver' || log.events.some((e) => e.name === 'game.completed');

  // ONLY return the raw, unredacted log to participants if the game has concluded!
  // Otherwise, active matches must ALWAYS be redacted to prevent Fog of War cheating via JSON inspection.
  if (isParticipant && isCompleted) {
    return log;
  }

  // 2. Otherwise, return redacted log
  return filterEventLogForPublic(log);
}

function toCompactEvent(event: PhalanxEvent, seq: number): CompactEvent {
  const base: CompactEvent = { seq, type: event.name };
  const p = event.payload;
  switch (event.name) {
    case 'match.created':
      return { ...base, params: p.params ?? null };
    case 'player.joined':
      return { ...base, p: p.playerIndex, bot: p.isBot ?? false };
    case 'game.initialized':
      return { ...base, stateHash: p.initialStateHash ?? null };
    case 'game.completed':
      return { ...base, winner: p.winnerIndex, reason: p.victoryType };
    default: {
      // Turn events: include payload but skip verbose stateHashAfter
      const rest = Object.fromEntries(Object.entries(p).filter(([k]) => k !== 'stateHashAfter'));
      return { ...base, ...rest };
    }
  }
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/** Scan past a JSON string literal (opening quote already at `start`). */
function scanJsonString(raw: string, start: number): number {
  let j = start + 1;
  while (j < raw.length) {
    if (raw[j] === '\\') {
      j += 2;
      continue;
    }
    if (raw[j] === '"') return j + 1;
    j++;
  }
  return j;
}

/** Scan past a JSON number starting at `start`. */
function scanJsonNumber(raw: string, start: number): number {
  let j = start;
  if (raw[j] === '-') j++;
  while (j < raw.length && /[\d.eE+-]/u.test(raw.charAt(j))) j++;
  return j;
}

const JSON_PUNCTUATION = new Set(['{', '}', '[', ']', ',', ':']);
const JSON_KEYWORDS: Record<string, { cls: string; len: number }> = {
  true: { cls: 'jb', len: 4 },
  false: { cls: 'jb', len: 5 },
  null: { cls: 'jz', len: 4 },
};

/**
 * Server-side JSON syntax highlighter — returns safe HTML with span tags.
 * Tokenizes the raw JSON string character-by-character so each value is
 * individually escaped before wrapping, preventing any XSS from payload content.
 */
function highlightJson(obj: unknown): string {
  const raw = JSON.stringify(obj, null, 2);
  let out = '';
  let i = 0;

  while (i < raw.length) {
    const ch = raw.charAt(i);

    if (ch === '"') {
      const end = scanJsonString(raw, i);
      const token = raw.slice(i, end);
      let k = end;
      while (k < raw.length && raw[k] === ' ') k++;
      out += `<span class="${raw[k] === ':' ? 'jk' : 'js'}">${escapeHtml(token)}</span>`;
      i = end;
    } else if (ch === '-' || (ch >= '0' && ch <= '9')) {
      const end = scanJsonNumber(raw, i);
      out += `<span class="jn">${escapeHtml(raw.slice(i, end))}</span>`;
      i = end;
    } else if (JSON_KEYWORDS[raw.slice(i, i + 5)] ?? JSON_KEYWORDS[raw.slice(i, i + 4)]) {
      const kw = JSON_KEYWORDS[raw.slice(i, i + 4)] ?? JSON_KEYWORDS[raw.slice(i, i + 5)];
      if (!kw) {
        i++;
        continue;
      }
      out += `<span class="${kw.cls}">${raw.slice(i, i + kw.len)}</span>`;
      i += kw.len;
    } else if (JSON_PUNCTUATION.has(ch)) {
      out += `<span class="jp">${escapeHtml(ch)}</span>`;
      i++;
    } else {
      out += escapeHtml(ch);
      i++;
    }
  }

  return out;
}

function renderEventLogHtml(
  matchId: string,
  events: PhalanxEvent[],
  fingerprint: string,
  generatedAt: string,
): string {
  const typeColors: Record<string, string> = {
    span_started: 'green',
    span_ended: 'orange',
    functional_update: 'cyan',
    system_error: 'red',
  };

  const rows = events
    .map((ev, seq) => {
      const color = typeColors[ev.type] ?? 'muted';
      const payloadHtml = highlightJson(ev.payload);
      const isError = ev.status === 'unrecoverable_error';
      const ts = escapeHtml(ev.timestamp).replace('T', ' ').replace('Z', ' UTC');
      return `<div class="event-row type-${escapeHtml(ev.type)}${isError ? ' is-error' : ''}" data-seq="${seq}">
  <div class="cell seq">${seq}</div>
  <div class="cell name-cell">
    <span class="expand-chevron">&#9654;</span><span class="event-name">${escapeHtml(ev.name)}</span>${isError ? '<span class="err-dot" title="unrecoverable_error">&#9679;</span>' : ''}
  </div>
  <div class="cell"><span class="badge badge-${color}">${escapeHtml(ev.type.replace(/_/g, ' '))}</span></div>
  <div class="cell ts">${ts}</div>
</div>
<div class="payload-row" id="p${seq}">
  <div class="payload-inner"><pre class="json-pre">${payloadHtml}</pre></div>
</div>`;
    })
    .join('\n');

  return `<!DOCTYPE html>
<html lang="en">
<head>
